import { Decoration, DecorationSet, EditorView, ViewPlugin, ViewUpdate } from "@codemirror/view";
import { Range, StateField, EditorState, StateEffect } from "@codemirror/state";
import { syntaxTree, ensureSyntaxTree } from "@codemirror/language";
import { DecorationFactory } from "./preview-logic/DecorationFactory";
import { HRWidget, BulletWidget, CheckboxWidget } from "./widgets/BaseWidgets";

const forceRefreshEffect = StateEffect.define<null>();

function buildDecorations(state: EditorState, basePath: string | null): DecorationSet {
    const builder: Range<Decoration>[] = [];
    const ranges = state.selection.ranges;
    const docLength = state.doc.length;
    const tree = ensureSyntaxTree(state, Math.min(docLength, 50000), 100) || syntaxTree(state);

    const isRangeActive = (from: number, to: number) => ranges.some(r => r.to >= from && r.from <= to);
    const isLineActive = (from: number, to: number) => {
        try {
            const line = state.doc.lineAt(from);
            return ranges.some(r => r.head >= line.from && r.head <= line.to);
        } catch { return false; }
    };

    tree.iterate({
        enter: (node) => {
            const { name: type, from, to } = node;
            if (from < 0 || to > docLength || from > to) return;

            // 1. 重逻辑节点 (由 Factory 处理)
            if (type === "FencedCode") builder.push(...DecorationFactory.handleFencedCode(node, state, isLineActive));
            else if (type === "Paragraph" || type === "Blockquote") builder.push(...DecorationFactory.handleMath(node, state, isRangeActive));
            else if (type === "Image") builder.push(...DecorationFactory.handleImage(node, state, isRangeActive, basePath));
            else if (type === "Table") builder.push(...DecorationFactory.handleTable(node, state, null));

            // 2. 轻逻辑节点 (直接处理)
            else if (type === "HeaderMark") {
                if (!isLineActive(from, to)) builder.push(Decoration.mark({ class: "cm-soft-hide" }).range(from, Math.min(to + 1, docLength)));
            } else if (type === "QuoteMark" || type === "EmphasisMark" || type === "StrikeThroughMark") {
                if (!isRangeActive(from, to)) builder.push(Decoration.mark({ class: "cm-soft-hide" }).range(from, to));
            } else if (type === "ListMark") {
                if (node.node.parent?.name !== "Task") {
                    const text = state.sliceDoc(from, to);
                    if ((text === "-" || text === "*") && !isLineActive(from, to)) {
                        builder.push(Decoration.replace({ widget: new BulletWidget() }).range(from, Math.min(to + 1, docLength)));
                    }
                } else if (!isLineActive(from, to)) {
                    builder.push(Decoration.mark({ class: "cm-soft-hide" }).range(from, to));
                }
            } else if (type === "HorizontalRule" && !isLineActive(from, to)) {
                builder.push(Decoration.replace({ widget: new HRWidget() }).range(from, to));
            } else if (type === "TaskMarker") {
                const checked = state.sliceDoc(from + 1, from + 2) === "x";
                builder.push(Decoration.replace({ widget: new CheckboxWidget(checked, from) }).range(from, to));
            } else if (type === "Link" && !isRangeActive(from, to)) {
                const linkMatch = /^\[(.*?)\]\((.*?)\)$/.exec(state.sliceDoc(from, to));
                if (linkMatch) {
                    builder.push(Decoration.mark({ class: "cm-soft-hide" }).range(from, from + 1));
                    builder.push(Decoration.mark({ class: "cm-link-text", attributes: { "data-url": linkMatch[2] } }).range(from + 1, from + 1 + linkMatch[1].length));
                    builder.push(Decoration.mark({ class: "cm-soft-hide" }).range(from + 1 + linkMatch[1].length, to));
                }
            }

            // 3. 样式增强 (无 Widget)
            if (type.startsWith("ATXHeading")) builder.push(Decoration.line({ class: `cm-heading-line cm-heading-${type.replace("ATXHeading", "")}` }).range(from));
            else if (type === "StrongEmphasis") builder.push(Decoration.mark({ class: "cm-bold-text" }).range(from, to));
            else if (type === "Emphasis") builder.push(Decoration.mark({ class: "cm-italic-text" }).range(from, to));
            else if (type === "StrikeThrough") builder.push(Decoration.mark({ class: "cm-strike-text" }).range(from, to));
            else if (type === "InlineCode") builder.push(Decoration.mark({ class: "cm-inline-code" }).range(from, to));
            else if (type === "Blockquote") {
                for (let l = state.doc.lineAt(from).number; l <= state.doc.lineAt(to).number; l++) {
                    builder.push(Decoration.line({ class: "cm-quote-line" }).range(state.doc.line(l).from));
                }
            }
        }
    });

    try {
        return Decoration.set(builder.sort((a, b) => a.from - b.from), true);
    } catch { return Decoration.none; }
}

const livePreviewStateField = (basePath: string | null) => StateField.define<DecorationSet>({
    create: (state) => buildDecorations(state, basePath),
    update: (decorations, tr) => (tr.docChanged || tr.selection || tr.effects.some(e => e.is(forceRefreshEffect)))
        ? buildDecorations(tr.state, basePath) : decorations.map(tr.changes),
    provide: f => EditorView.decorations.from(f)
});

const syntaxWatchPlugin = ViewPlugin.fromClass(class {
    private lastTreeLen = 0;
    update(update: ViewUpdate) {
        const treeLen = syntaxTree(update.state).length;
        if (treeLen > this.lastTreeLen) {
            this.lastTreeLen = treeLen;
            setTimeout(() => update.view.dispatch({ effects: forceRefreshEffect.of(null) }), 10);
        }
    }
});

export const createLivePreview = (basePath: string | null) => [livePreviewStateField(basePath), syntaxWatchPlugin];
export { forceRefreshEffect };

import { WidgetType, EditorView } from "@codemirror/view";

export class CopyButtonWidget extends WidgetType {
  constructor(readonly codeContent: string) { super(); }

  eq(other: CopyButtonWidget) {
    // 内容不变时不重绘
    return other.codeContent === this.codeContent;
  }

  // 关键：告诉 CodeMirror 忽略此 DOM 的事件，防止光标焦点问题
  ignoreEvent() { return true; }

  toDOM(_view: EditorView) {
    const span = document.createElement("span");
    span.className = "cm-copy-btn";
    span.title = "Copy Code";

    // 默认图标 (Copy)
    span.innerHTML = `<svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><rect x="9" y="9" width="13" height="13" rx="2" ry="2"></rect><path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1"></path></svg>`;

    // 点击事件
    span.onmousedown = (e) => {
      e.preventDefault(); // 阻止默认行为
      e.stopPropagation(); // 防止触发编辑器光标移动

      navigator.clipboard.writeText(this.codeContent).then(() => {
        const originalHTML = span.innerHTML;
        // 成功反馈图标 (Check)
        span.innerHTML = `<svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="#22c55e" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><polyline points="20 6 9 17 4 12"></polyline></svg>`;
        setTimeout(() => span.innerHTML = originalHTML, 1500);
      }).catch(err => {
        console.error("Copy failed:", err);
      });
    };

    return span;
  }
}

import { WidgetType, EditorView } from "@codemirror/view";

const COPY_ICON = `<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><rect x="9" y="9" width="13" height="13" rx="2" ry="2"></rect><path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1"></path></svg>`;
const CHECK_ICON = `<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="#4ade80" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><polyline points="20 6 9 17 4 12"></polyline></svg>`;

function escapeRegExp(string: string) { return string.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'); }

/**
 * 将图片 Blob 转换为 PNG Blob，因为 navigator.clipboard.write 通常只支持 PNG。
 */
async function convertToPng(blob: Blob): Promise<Blob> {
    if (blob.type === "image/png") return blob;

    return new Promise((resolve, reject) => {
        const img = new Image();
        const url = URL.createObjectURL(blob);
        img.onload = () => {
            const canvas = document.createElement("canvas");
            canvas.width = img.width;
            canvas.height = img.height;
            const ctx = canvas.getContext("2d");
            if (!ctx) {
                reject(new Error("Failed to get canvas context"));
                return;
            }
            ctx.drawImage(img, 0, 0);
            canvas.toBlob((result) => {
                URL.revokeObjectURL(url);
                if (result) resolve(result);
                else reject(new Error("Failed to convert to PNG"));
            }, "image/png");
        };
        img.onerror = () => {
            URL.revokeObjectURL(url);
            reject(new Error("Failed to load image for conversion"));
        };
        img.src = url;
    });
}

export class ImageWidget extends WidgetType {
    constructor(
        readonly src: string,
        readonly alt: string,
        readonly width: string | undefined,
        readonly basePath: string | null
    ) { super(); }

    eq(other: ImageWidget) {
        return other.src === this.src &&
            other.alt === this.alt &&
            other.width === this.width &&
            other.basePath === this.basePath;
    }

    ignoreEvent(_event: Event) { return true; }

    toDOM(view: EditorView) {
        const container = document.createElement("div");
        container.className = "cm-img-container group relative inline-block";

        // === 尺寸修复 ===
        // 如果有数值，设为百分比；如果没有，保持默认行为 (由 max-width 限制)
        if (this.width) {
            container.style.width = `${this.width}%`;
        } else {
            // 让图片原比例显示，受 CSS max-width: 100% 限制
            container.style.width = 'auto';
        }

        let finalSrc = this.src;
        if (!this.src.startsWith('http') && !this.src.startsWith('data:') && !this.src.startsWith('local-resource:')) {
            if (this.basePath) {
                // 规范化路径分隔符
                const cleanBasePath = this.basePath.replace(/\\/g, '/');
                const cleanSrc = this.src.replace(/^\.\//, '').replace(/\\/g, '/');

                // 拼接绝对路径
                let fullPath = cleanBasePath;
                if (!fullPath.endsWith('/')) fullPath += '/';
                fullPath += cleanSrc;

                // 移除重复斜杠（保留盘符后的斜杠）
                fullPath = fullPath.replace(/([^:])\/\/+/g, '$1/');

                // 关键：必须使用 encodeURI 处理路径部分，以支持空格等特殊字符。
                // encodeURI 不会编码盘符 ":"，因此在 Windows 下是安全的。
                finalSrc = `local-resource:///${encodeURI(fullPath)}`;
            }
        }

        const img = document.createElement("img");
        img.src = finalSrc;
        img.alt = this.alt;
        img.className = "cm-img-widget rounded-md shadow-sm border border-transparent hover:border-primary/50 transition-all";

        img.onload = () => view.requestMeasure();

        img.ondblclick = (e) => {
            e.preventDefault();
            e.stopPropagation();
            window.dispatchEvent(new CustomEvent('preview-image-event', { detail: { src: finalSrc } }));
        };

        const toolbar = document.createElement("div");
        toolbar.className = "absolute top-2 right-2 flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity bg-black/60 backdrop-blur-sm rounded-md p-1 z-10";

        const copyBtn = document.createElement("button");
        copyBtn.className = "p-1 text-white hover:text-green-400 transition-colors rounded cursor-pointer";
        copyBtn.title = "复制图片";
        copyBtn.innerHTML = COPY_ICON;

        copyBtn.onclick = async (e) => {
            e.preventDefault(); e.stopPropagation();
            try {
                const response = await fetch(finalSrc);
                let blob = await response.blob();

                // 转换非 PNG 图片为 PNG，以适配剪贴板 API
                if (blob.type !== "image/png") {
                    blob = await convertToPng(blob);
                }

                await navigator.clipboard.write([new ClipboardItem({ [blob.type]: blob })]);
                copyBtn.innerHTML = CHECK_ICON;
                setTimeout(() => copyBtn.innerHTML = COPY_ICON, 1500);
            } catch (err) { console.error("Copy failed:", err); }
        };

        const resizeWrapper = document.createElement("div");
        resizeWrapper.className = "flex items-center text-white px-1 border-l border-white/20 ml-1";

        const input = document.createElement("input");
        input.type = "text";
        input.className = "w-8 bg-transparent border-none text-right text-xs font-mono focus:outline-none text-white p-0 m-0 h-auto";
        // 默认显示空或 "Auto"
        input.placeholder = "Auto";
        input.value = this.width || "";

        const unit = document.createElement("span");
        unit.className = "text-[10px] ml-0.5 opacity-70";
        unit.textContent = "%";

        const commitChange = () => {
            let val = input.value.trim();

            // 如果清空，还原为默认
            if (!val) {
                if (!this.width) return; // 没变
                val = ""; // 清除属性
            } else {
                // 校验数值
                let num = parseInt(val);
                if (isNaN(num)) num = 100;
                if (num < 10) num = 10;
                if (num > 100) num = 100;
                val = num.toString();
            }

            if (val === (this.width || "")) return;

            // 延迟 dispatch，避免在 CodeMirror 更新过程中触发
            setTimeout(() => {
                const pos = view.posAtDOM(container);
                if (pos === -1) return;

                const line = view.state.doc.lineAt(pos);
                const regex = new RegExp(`!\\[${escapeRegExp(this.alt)}(?:\\|\\d+)?\\]\\(${escapeRegExp(this.src)}\\)`);
                const match = regex.exec(line.text);

                if (match) {
                    const start = line.from + match.index;
                    const end = start + match[0].length;
                    const widthPart = val ? `|${val}` : '';
                    const newText = `![${this.alt}${widthPart}](${this.src})`;
                    view.dispatch({ changes: { from: start, to: end, insert: newText } });
                }
            }, 0);
        };

        input.onkeydown = (e) => {
            if (e.key === 'Enter') { e.preventDefault(); e.stopPropagation(); commitChange(); }
        };
        input.onblur = () => commitChange();
        input.onmousedown = (e) => e.stopPropagation();

        resizeWrapper.appendChild(input);
        resizeWrapper.appendChild(unit);
        toolbar.appendChild(copyBtn);
        toolbar.appendChild(resizeWrapper);
        container.appendChild(img);
        container.appendChild(toolbar);

        return container;
    }
}

import { WidgetType, EditorView } from "@codemirror/view";
import { TableData, parseMarkdownTable, generateMarkdown, findTableEndPosition } from "../../utils/tableUtils";
import { TableInteractionManager } from "./table/TableInteractionManager";
import { TableClipboardService } from "./table/TableClipboardService";

/**
 * Table Widget - 表格实时渲染扩展
 * 
 * 核心逻辑已解耦至：
 * 1. tableUtils.ts (算法)
 * 2. TableInteractionManager.ts (交互)
 * 3. TableClipboardService.ts (剪贴板)
 */
export class TableWidget extends WidgetType {
    private tableData: TableData;
    private tableText: string;
    private isDragging = false;
    private dragType: 'col' | 'row' | 'rect' | null = null;
    private dragStartIndex: number = -1;

    constructor(data: TableData, text: string) {
        super();
        this.tableData = data;
        this.tableText = text;
    }

    eq(other: TableWidget) {
        return other.tableText === this.tableText &&
            other.tableData.from === this.tableData.from &&
            other.tableData.to === this.tableData.to;
    }

    ignoreEvent(event: Event) {
        return event.type === 'mousedown' || event.type === 'click';
    }

    private isEditingText(target: HTMLElement): boolean {
        return target.getAttribute('contenteditable') === 'true';
    }

    toDOM(view: EditorView) {
        const container = document.createElement("div");
        container.className = "cm-table-widget";
        container.setAttribute('tabindex', '-1');

        // 阻止默认 Keymap 干扰
        container.addEventListener('keydown', (e) => {
            if (this.isEditingText(e.target as HTMLElement)) e.stopPropagation();
        }, true);

        // 剪贴板对接
        container.addEventListener('copy', (e) => TableClipboardService.handleCopy(e, container));

        // 构建工具栏
        const toolbar = document.createElement("div");
        toolbar.className = "cm-table-toolbar";

        const createBtn = (text: string, onClick: () => void, danger = false) => {
            const btn = document.createElement("button");
            btn.className = `cm-table-btn ${danger ? 'cm-table-btn-danger' : ''}`;
            btn.innerText = text;
            btn.onclick = (e) => { e.preventDefault(); e.stopPropagation(); onClick(); };
            return btn;
        };

        toolbar.appendChild(createBtn("加行", () => this.addRow(view, container)));
        toolbar.appendChild(createBtn("加列", () => this.addCol(view, container)));
        toolbar.appendChild(createBtn("删除表格", () => this.deleteTable(view, container), true));

        container.appendChild(toolbar);

        // 构建表格本体
        const table = document.createElement("table");
        table.className = "cm-rendered-table";

        // Header
        const thead = document.createElement("thead");
        const headerRow = document.createElement("tr");
        this.tableData.headers.forEach((h, i) => {
            const th = document.createElement("th");
            th.innerText = h;
            this.attachCellListeners(th, view, container);

            // 行选择逻辑对接
            th.onmousedown = (e) => {
                if (e.detail === 2) { th.contentEditable = "true"; th.focus(); return; }
                this.isDragging = true; this.dragType = 'col'; this.dragStartIndex = i;
                TableInteractionManager.selectColumnRange(container, i, i);
            };
            th.onmouseenter = (e) => {
                if (this.isDragging && this.dragType === 'col') TableInteractionManager.selectColumnRange(container, this.dragStartIndex, i);
            };
            headerRow.appendChild(th);
        });
        thead.appendChild(headerRow);
        table.appendChild(thead);

        // Body
        const tbody = document.createElement("tbody");
        this.tableData.rows.forEach((rowData, rIdx) => {
            const tr = document.createElement("tr");
            rowData.forEach((cellText, cIdx) => {
                const td = document.createElement("td");
                td.innerText = cellText;
                this.attachCellListeners(td, view, container);

                // 矩形选择逻辑对接
                td.onmousedown = (e) => {
                    if (e.detail === 2) { td.contentEditable = "true"; td.focus(); return; }
                    this.isDragging = true; this.dragType = 'rect';
                    this.dragStartIndex = rIdx * 1000 + cIdx;
                    TableInteractionManager.selectRect(container, rIdx, cIdx, rIdx, cIdx);
                };
                td.onmouseenter = () => {
                    if (this.isDragging && this.dragType === 'rect') {
                        const sR = Math.floor(this.dragStartIndex / 1000), sC = this.dragStartIndex % 1000;
                        TableInteractionManager.selectRect(container, sR, sC, rIdx, cIdx);
                    }
                };
                tr.appendChild(td);
            });
            tbody.appendChild(tr);
        });
        table.appendChild(tbody);
        container.appendChild(table);

        // 全局拖拽清理
        const upHandler = () => { this.isDragging = false; this.dragType = null; };
        window.addEventListener('mouseup', upHandler);
        container.addEventListener('click', (e) => {
            if (!(e.target as HTMLElement).closest('td, th')) TableInteractionManager.clearSelection(container);
        });

        return container;
    }

    private attachCellListeners(cell: HTMLElement, view: EditorView, container: HTMLElement) {
        cell.onblur = () => {
            cell.contentEditable = "false";
            this.saveChanges(view, container);
        };
        cell.oninput = () => this.saveChanges(view, container);
    }

    private addRow(view: EditorView, container: HTMLElement) {
        const data = this.getTableDataFromDOM(container);
        if (data) {
            data.rows.push(Array(data.headers.length).fill('内容'));
            this.updateDocument(view, data);
        }
    }

    private addCol(view: EditorView, container: HTMLElement) {
        const data = this.getTableDataFromDOM(container);
        if (data) {
            data.headers.push('新列');
            data.rows = data.rows.map(r => [...r, '内容']);
            this.updateDocument(view, data);
        }
    }

    private deleteTable(view: EditorView, container: HTMLElement) {
        const end = findTableEndPosition(view, this.tableData.from);
        view.dispatch({ changes: { from: this.tableData.from, to: end, insert: '' } });
    }

    private saveChanges(view: EditorView, container: HTMLElement) {
        const data = this.getTableDataFromDOM(container);
        if (data) this.updateDocument(view, data);
    }

    private updateDocument(view: EditorView, data: TableData) {
        const markdown = generateMarkdown(data.headers, data.rows);
        const end = findTableEndPosition(view, this.tableData.from);
        view.dispatch({ changes: { from: this.tableData.from, to: end, insert: markdown } });
    }

    private getTableDataFromDOM(container: HTMLElement): TableData | null {
        const table = container.querySelector('table');
        if (!table) return null;

        const headers = Array.from(table.querySelectorAll('thead th')).map(th => (th as HTMLElement).innerText);
        const rows = Array.from(table.querySelectorAll('tbody tr')).map(tr =>
            Array.from(tr.querySelectorAll('td')).map(td => (td as HTMLElement).innerText)
        );

        return { headers, rows, from: this.tableData.from, to: this.tableData.to };
    }
}

export { parseMarkdownTable };

