import React, { useImperativeHandle, useRef, useEffect, useCallback, useMemo } from 'react';
import CodeMirror, { ReactCodeMirrorRef } from '@uiw/react-codemirror';
import { EditorView } from '@codemirror/view';
import { EditorState } from '@codemirror/state';
import { githubLight } from '@uiw/codemirror-theme-github';
import { oneDark } from '@codemirror/theme-one-dark';
import { createDynamicTheme } from '../config/themeAdaptor';
import { useThemeStore } from '@/shared/stores/themeStore';
import { IEditorRef, EditorCommand } from '../framework/types';
import { createLivePreview } from '../cm-extensions/livePreview';
import { createEditorSetup } from '../config/editorSetup';
import { useService } from '@/kernel/core/KernelContext';
import { useEditorTabsStore } from '../stores/editorTabsStore';
import { IFileSystem } from '@/kernel/interfaces/IFileSystem';
import { useOutlineStore } from '@/modules/outline/store';
import { parseOutline } from '@/modules/outline/utils/parser';
import { getDirnameSync } from '@/shared/utils/path';
import { EditorExtensionRegistry } from '@/modules/plugin/EditorExtensionRegistry';

// === [EXTRACTED MODULES] ===
import { activeMatchField } from '../cm-extensions/searchHighlight';
import { excelTableTheme, editorCoreLayout } from '../cm-extensions/theme';
import { useEditorMedia } from '../hooks/useEditorMedia';
import { EditorCommandService } from '../services/EditorCommandService';

interface CodeMirrorEditorProps {
    initialContent: string;
    onUpdate: (content: string) => void;
    editorRef?: React.MutableRefObject<IEditorRef | null>;
    className?: string;
    viewMode: 'source' | 'preview';
    currentFilePath: string | null;
    onActiveStateChange?: (states: Record<string, boolean>) => void;
    showSourceOnHover?: boolean;
    readOnly?: boolean;
    onScrollPercentage?: (percentage: number) => void;
}

export function CodeMirrorEditor({
    initialContent, onUpdate, editorRef, className, viewMode, currentFilePath,
    onActiveStateChange, readOnly = false, onScrollPercentage
}: CodeMirrorEditorProps) {
    const { themes, currentThemeId } = useThemeStore();
    const currentTheme = themes.find(t => t.id === currentThemeId) || themes[0];
    const isDark = currentTheme.type === 'dark';

    const cmRef = useRef<ReactCodeMirrorRef>(null);
    const containerRef = useRef<HTMLDivElement>(null);
    const setHeaders = useOutlineStore((state) => state.setHeaders);
    const extensionRegistry = useService<EditorExtensionRegistry>('editorExtensionRegistry');

    const basePath = useMemo(() => currentFilePath ? getDirnameSync(currentFilePath) : null, [currentFilePath]);

    // [DECOUPLED] Use specialized hooks and services
    const { handlePaste, insertImage } = useEditorMedia(basePath);
    const pendingRestoreRef = useRef<any>(null);
    const initialContentRef = useRef(initialContent);
    const lastAppliedPathRef = useRef<string | null>(null);

    useEffect(() => {
        initialContentRef.current = initialContent;
        if (currentFilePath !== lastAppliedPathRef.current) lastAppliedPathRef.current = null;
    }, [currentFilePath, initialContent]);

    // [DECOUPLED] Handle link clicks via delegation
    const fileSystem = useService<IFileSystem>('fileSystem');
    const handleClick = useCallback((event: MouseEvent) => {
        if (!event.ctrlKey && !event.metaKey) return false;
        const url = (event.target as HTMLElement).closest('.cm-link-text')?.getAttribute('data-url');
        if (url) { fileSystem?.openExternal(url); event.preventDefault(); return true; }
        return false;
    }, [fileSystem]);

    const stableExtensions = useMemo(() => {
        const setup = createEditorSetup({ handlePaste, handleClick, onUpdate, onActiveStateChange });
        return [
            ...setup,
            activeMatchField,
            excelTableTheme,
            editorCoreLayout,
            ...(viewMode === 'preview' ? createLivePreview(basePath) : []),
            ...(extensionRegistry?.getExtensions() || []),
            EditorView.updateListener.of((update) => {
                if (update.docChanged) setHeaders(parseOutline(update.view));
                if (update.geometryChanged && onScrollPercentage) {
                    const scroller = update.view.scrollDOM;
                    const scrollHeight = scroller.scrollHeight - scroller.clientHeight;
                    if (scrollHeight > 0) onScrollPercentage(scroller.scrollTop / scrollHeight);
                }
            })
        ];
    }, [basePath, handlePaste, handleClick, viewMode, onUpdate, onActiveStateChange, extensionRegistry, onScrollPercentage, setHeaders]);

    useImperativeHandle(editorRef, () => ({
        getContent: () => cmRef.current?.view?.state.doc.toString() || '',
        setContent: (content: string) => {
            const view = cmRef.current?.view;
            if (view) view.dispatch({ changes: { from: 0, to: view.state.doc.length, insert: content } });
        },
        getScrollState: () => {
            const view = cmRef.current?.view;
            if (!view) return { cursorPosition: 0, scrollTop: 0, topLineNumber: 1, topOffset: 0 };
            const cursorPosition = view.state.selection.main.head;
            const scrollTop = view.scrollDOM.scrollTop;
            const lineBlock = view.lineBlockAtHeight(scrollTop);
            const lineNumber = view.state.doc.lineAt(lineBlock.from).number;
            return { cursorPosition, scrollTop, topLineNumber: lineNumber, topOffset: lineBlock.top - scrollTop };
        },
        resetState: (content: string, cursorPosition?: number, scrollTop?: number, topLineNumber?: number, topOffset?: number) => {
            const view = cmRef.current?.view;
            if (!view) return;
            view.setState(EditorState.create({
                doc: content,
                extensions: stableExtensions,
                selection: { anchor: cursorPosition !== undefined ? Math.min(cursorPosition, content.length) : 0 }
            }));

            if (topLineNumber && topLineNumber > 0) {
                pendingRestoreRef.current = { lineNumber: topLineNumber, offset: topOffset || 0 };
            }

            requestAnimationFrame(() => {
                if (pendingRestoreRef.current && view.scrollDOM) {
                    try {
                        const linePos = view.state.doc.line(Math.min(pendingRestoreRef.current.lineNumber, view.state.doc.lines)).from;
                        view.requestMeasure();
                        view.scrollDOM.scrollTop = view.lineBlockAt(linePos).top - pendingRestoreRef.current.offset;
                    } catch (e) { }
                } else if (scrollTop !== undefined && view.scrollDOM) {
                    view.scrollDOM.scrollTop = scrollTop;
                }
                lastAppliedPathRef.current = currentFilePath;
            });
            setHeaders(parseOutline(view));
        },
        insertImage: (file: File) => {
            const view = cmRef.current?.view;
            if (view) insertImage(view, file);
        },
        executeCommand: (cmd: EditorCommand, params?: any) => {
            const view = cmRef.current?.view;
            if (view) EditorCommandService.execute(view, cmd, params);
        },
        view: cmRef.current?.view,
        getActiveStates: () => ({})
    }));

    // Cleanup & Observer logic
    useEffect(() => {
        const view = cmRef.current?.view;
        const scroller = view?.scrollDOM;
        if (!view || !scroller) return;

        const attemptAlign = () => {
            if (pendingRestoreRef.current) {
                try {
                    const linePos = view.state.doc.line(Math.min(pendingRestoreRef.current.lineNumber, view.state.doc.lines)).from;
                    view.requestMeasure();
                    scroller.scrollTop = view.lineBlockAt(linePos).top - pendingRestoreRef.current.offset;
                } catch (e) { }
            }
        };

        const resizeObserver = new ResizeObserver(() => requestAnimationFrame(attemptAlign));
        if (view.contentDOM) resizeObserver.observe(view.contentDOM);

        let scrollTimeout: NodeJS.Timeout;
        const handleScroll = () => {
            if (currentFilePath && lastAppliedPathRef.current === currentFilePath && !pendingRestoreRef.current) {
                clearTimeout(scrollTimeout);
                scrollTimeout = setTimeout(() => {
                    const view = cmRef.current?.view;
                    if (!view) return;
                    const scrollTop = view.scrollDOM.scrollTop;
                    const lineBlock = view.lineBlockAtHeight(scrollTop);
                    const lineNumber = view.state.doc.lineAt(lineBlock.from).number;
                    useEditorTabsStore.getState().setTabCursor(currentFilePath, view.state.selection.main.head, scrollTop, lineNumber, lineBlock.top - scrollTop);
                }, 150);
            }
        };
        scroller.addEventListener('scroll', handleScroll, { passive: true });

        return () => {
            resizeObserver.disconnect();
            scroller.removeEventListener('scroll', handleScroll);
            clearTimeout(scrollTimeout);
        };
    }, [currentFilePath]);

    return (
        <div ref={containerRef} className={`h-full w-full text-base ${className}`}>
            <CodeMirror
                ref={cmRef}
                value={initialContentRef.current}
                onChange={onUpdate}
                height="100%"
                theme={[isDark ? oneDark : githubLight, createDynamicTheme(isDark)]}
                extensions={stableExtensions}
                basicSetup={{
                    lineNumbers: viewMode === 'source',
                    foldGutter: true,
                    highlightActiveLine: false,
                    bracketMatching: true,
                    closeBrackets: true,
                    autocompletion: false,
                    searchKeymap: false,
                }}
                readOnly={readOnly}
                style={{ height: '100%' }}
                className="cm-editor-container custom-scrollbar"
            />
            <style>{`.cm-editor-container .cm-content { font-family: ${viewMode === 'source' ? "'JetBrains Mono', monospace" : "'Segoe UI', sans-serif"}; }`}</style>
        </div>
    );
}

/**
 * EditorKernelIntegration.tsx
 * 
 * 职责：
 * 1. 监听 Editor 内部状态 (activeTabId) 并同步到 Shared 层 (workspaceStore)
 * 2. 监听 Kernel 事件 (如 FILE_MOVED) 并调用 Editor 内部方法更新状态
 * 3. 检测外部文件系统变化，同步关闭无效标签页 (Bug 2 修复)
 * 
 * 目的：
 * 实现 Editor 模块与 Explorer 模块的解耦。Explorer 不再直接调用 Editor 的 store，
 * 而是通过 workspaceStore 读取状态，通过 Kernel 事件触发操作。
 */

import { useEffect, useCallback } from 'react';
import { useEditorTabsStore } from '../stores/editorTabsStore';
import { useWorkspaceStore } from '@/shared/stores/workspaceStore';
import { useKernelEvent } from '@/kernel/hooks/useKernelEvent';
import { useService } from '@/kernel/core/KernelContext';
import { IFileSystem } from '@/kernel/interfaces/IFileSystem';

export function EditorKernelIntegration() {
    // Editor Store (内部状态)
    const { activeTabId, updateTabPath, tabs, closeTab } = useEditorTabsStore();
    const fileSystem = useService<IFileSystem>('fileSystem');

    // Shared Store (公共状态)
    const { setSelectedFilePath } = useWorkspaceStore();

    // 1. 同步 Active Tab 到 Shared Store
    // 这样 Explorer 就可以通过 workspaceStore 知道当前选中的文件，而不需要依赖 editorTabsStore
    useEffect(() => {
        // activeTabId 即为 filePath (归一化后)
        setSelectedFilePath(activeTabId);
    }, [activeTabId, setSelectedFilePath]);

    // 2. 监听文件移动/重命名事件
    // Explorer 移动文件后发射此事件，Editor 响应更新标签页路径
    useKernelEvent('FILE_MOVED', (payload) => {
        console.log('[EditorKernelIntegration] Received FILE_MOVED:', payload);
        updateTabPath(payload.oldPath, payload.newPath);
    });

    // 3. Bug 2 修复：检测外部文件系统变化后标签页有效性
    // 当 FS Watcher 检测到变化时，检查每个打开的标签页对应的文件是否仍然存在
    const checkTabsExistence = useCallback(async () => {
        console.log('[EditorKernelIntegration] Checking tabs existence...');
        const currentTabs = useEditorTabsStore.getState().tabs;

        for (const tab of currentTabs) {
            // 跳过 untitled 临时文件
            if (tab.id.startsWith('untitled-')) continue;

            const exists = await fileSystem.checkExists(tab.path);
            if (!exists) {
                console.log(`[EditorKernelIntegration] File no longer exists: ${tab.path}`);
                // 关闭不存在的标签页
                closeTab(tab.id);
            }
        }
    }, [fileSystem, closeTab]);

    useKernelEvent('CHECK_TABS_EXISTENCE', checkTabsExistence);

    return null; // 逻辑组件，无 UI
}

import React, { useRef, useState, useEffect, useCallback } from 'react';
import {
  Bold, Italic, Strikethrough, Code, Heading1, Heading2,
  List, ListOrdered, Quote, Undo, Redo,
  CheckSquare, Image as ImageIcon, Link as LinkIcon,
  AlignLeft, AlignCenter, AlignRight, Table2
} from 'lucide-react';
import { cn } from '@/shared/utils';
import { InputDialog } from '@/shared/components/ui/InputDialog';
import { IEditorRef, EditorCommand } from '../framework/types';
import { useService } from '@/kernel/core/KernelContext';
import { EditorToolbarRegistry, IEditorToolbarItem } from '../EditorToolbarRegistry';

interface EditorToolbarProps {
  editorRef: React.MutableRefObject<IEditorRef | null>;
  activeStates: Record<string, boolean>;
}

interface ToggleButtonProps {
  onClick?: () => void;
  icon: React.ElementType;
  isActive?: boolean;
  title: string;
  onMouseDown?: (e: React.MouseEvent) => void;
  className?: string;
}

const ToggleButton = React.forwardRef<HTMLButtonElement, ToggleButtonProps>(
  ({ onClick, icon: Icon, isActive, title, onMouseDown, className }, ref) => (
    <button
      ref={ref}
      onMouseDown={(e) => {
        // Prevent focus loss from editor
        e.preventDefault();
        if (onMouseDown) onMouseDown(e);
      }}
      onClick={onClick}
      className={cn(
        "p-1.5 rounded transition-colors",
        isActive ? "bg-primary/10 text-primary" : "hover:bg-black/5 dark:hover:bg-white/10 text-muted-foreground",
        className
      )}
      title={title}
    >
      <Icon className="w-4 h-4" />
    </button>
  )
);

export function EditorToolbar({ editorRef, activeStates }: EditorToolbarProps) {
  const registry = useService<EditorToolbarRegistry>('editorToolbarRegistry');
  const [items, setItems] = useState<IEditorToolbarItem[]>(registry.getItems());

  useEffect(() => {
    return registry.subscribe(() => {
      setItems(registry.getItems());
    });
  }, [registry]);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const [linkModalOpen, setLinkModalOpen] = useState(false);

  const exec = useCallback((cmd: EditorCommand, val?: any) => {
    editorRef.current?.executeCommand(cmd, val);
  }, [editorRef]);

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && editorRef.current) {
      await editorRef.current.insertImage(file);
    }
    e.target.value = '';
  };

  // 渲染组件类型或按钮类型的注册项
  const renderRegistryItems = (group: string) => {
    return items
      .filter(item => item.group === group)
      .map(item => {
        if (item.type === 'custom' && item.render) {
          return <React.Fragment key={item.id}>{item.render({ editorRef, activeStates })}</React.Fragment>;
        }
        return (
          <ToggleButton
            key={item.id}
            onClick={() => item.onClick?.(editorRef)}
            icon={item.icon}
            isActive={activeStates[item.id]} // 假设 id 对应状态 key，或者由插件处理
            title={item.label}
          />
        );
      });
  };

  return (
    <>
      <div className="flex flex-col border-b border-border/40 bg-editor-background sticky top-0 z-20">
        <div className="flex items-center gap-0.5 px-3 py-1.5 overflow-x-auto custom-scrollbar select-none">
          <ToggleButton onClick={() => exec('BOLD')} isActive={activeStates['StrongEmphasis']} icon={Bold} title="加粗" />
          <ToggleButton onClick={() => exec('ITALIC')} isActive={activeStates['Emphasis']} icon={Italic} title="斜体" />
          <ToggleButton onClick={() => exec('STRIKE')} isActive={activeStates['StrikeThrough']} icon={Strikethrough} title="删除线" />
          <ToggleButton onClick={() => exec('CODE')} isActive={activeStates['InlineCode']} icon={Code} title="行内代码" />

          <div className="w-[1px] h-4 bg-border/50 mx-1" />
          <ToggleButton onClick={() => exec('H1')} isActive={activeStates['ATXHeading1']} icon={Heading1} title="一级标题" />
          <ToggleButton onClick={() => exec('H2')} isActive={activeStates['ATXHeading2']} icon={Heading2} title="二级标题" />

          <div className="w-[1px] h-4 bg-border/50 mx-1" />
          <ToggleButton onClick={() => exec('UL')} isActive={activeStates['BulletList']} icon={List} title="无序列表" />
          <ToggleButton onClick={() => exec('OL')} isActive={activeStates['OrderedList']} icon={ListOrdered} title="有序列表" />
          <ToggleButton onClick={() => exec('TASK')} isActive={activeStates['Task']} icon={CheckSquare} title="任务列表" />
          <ToggleButton onClick={() => exec('QUOTE')} isActive={activeStates['Blockquote']} icon={Quote} title="引用" />
          <ToggleButton onClick={() => exec('TABLE')} icon={Table2} title="插入表格" />

          <div className="w-[1px] h-4 bg-border/50 mx-1" />
          <ToggleButton icon={AlignLeft} title="左对齐" />
          <ToggleButton icon={AlignCenter} title="居中" />
          <ToggleButton icon={AlignRight} title="右对齐" />

          <div className="w-[1px] h-4 bg-border/50 mx-1" />

          {/* 渲染注入的 Insert 分组项 (如 Math, Emoji) */}
          {renderRegistryItems('insert')}

          <ToggleButton onClick={() => setLinkModalOpen(true)} isActive={activeStates['Link']} icon={LinkIcon} title="链接" />
          <ToggleButton onClick={() => fileInputRef.current?.click()} isActive={activeStates['Image']} icon={ImageIcon} title="图片" />
          <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleImageUpload} />

          <div className="w-[1px] h-4 bg-border/50 mx-1" />
          <ToggleButton onClick={() => exec('UNDO')} icon={Undo} title="撤销" />
          <ToggleButton onClick={() => exec('REDO')} icon={Redo} title="重做" />

          {/* 渲染其他分组项 */}
          {renderRegistryItems('other')}
        </div>

        <InputDialog
          isOpen={linkModalOpen}
          title="插入链接"
          placeholder="https://example.com"
          onConfirm={(val) => {
            exec('LINK', val);
            setLinkModalOpen(false);
          }}
          onCancel={() => setLinkModalOpen(false)}
        />
      </div>
    </>
  );
}

