import React, { useEffect, useRef, useState, useCallback } from 'react';
import { useKernel } from '@/kernel/core/KernelContext';
import { useEditorLogic } from '../hooks/useEditorLogic';
import { useEditorStore } from '../store/editorStore';
import { useFileStore } from '@/modules/explorer/store';
import { useLayoutStore } from '@/shared/stores/layoutStore';
import { useEditorTabsStore } from '../stores/editorTabsStore';
import { EditorSyncService } from '../services/EditorSyncService';
import { EditorPanelRegistry } from '../registries/EditorPanelRegistry';
import { IEditorRef } from '../framework/types';

// Sub Components & Hooks
import { EditorHeader } from './sub/EditorHeader';
import { EditorMainView } from './sub/EditorMainView';
import { EditorModals } from './sub/EditorModals';
import { EditorTabs } from './EditorTabs';
import { EditorToolbar } from './EditorToolbar';
import { EditorKernelIntegration } from './EditorKernelIntegration';
import { useEditorEvents } from '../hooks/useEditorEvents';

export function NoteEditor() {
  const kernel = useKernel();
  const panelRegistry = kernel.getService<EditorPanelRegistry>('editorPanelRegistry');
  const syncService = useRef(new EditorSyncService());
  const [panels, setPanels] = useState(panelRegistry.getVisiblePanels());

  // Global & Module Logic States
  const { currentPath, initialContent, isUnsaved, handleContentUpdate, saveFile, fileName, loadedPath } = useEditorLogic();
  const { headingNumbering, viewMode, isSplitView, setSplitView, setSaveAsDialogOpen } = useEditorStore();
  const { selectPath } = useFileStore();
  const { isZenMode } = useLayoutStore();
  const { openTab, setTabDirty, getTabCursor } = useEditorTabsStore();

  // Refs & Local Syncing State
  const editorRef = useRef<IEditorRef | null>(null);
  const previewEditorRef = useRef<IEditorRef | null>(null);
  const liveContentRef = useRef<string>(initialContent);
  const isSyncingRef = useRef(false);
  const cursorLineRef = useRef<number>(1);
  const prevPathRef = useRef<string | null>(null);

  const [previewSrc, setPreviewSrc] = useState<string | null>(null);
  const [activeStates, setActiveStates] = useState<Record<string, boolean>>({});

  // 1. Structural Subscriptions & Disposals
  useEffect(() => { liveContentRef.current = initialContent; }, [initialContent, currentPath]);
  useEffect(() => { return panelRegistry.subscribe(() => setPanels(panelRegistry.getVisiblePanels())); }, [panelRegistry]);
  useEffect(() => { return () => syncService.current.dispose(); }, []);
  useEffect(() => { syncService.current.setViews(editorRef.current?.view || null, previewEditorRef.current?.view || null); }, [isSplitView]);

  // 2. Editor Update Logic (Internal to NoteEditor context)
  const handleEditorUpdate = useCallback((val: string) => {
    if (isSyncingRef.current) { liveContentRef.current = val; return; }
    liveContentRef.current = val;
    handleContentUpdate(val);

    const view = editorRef.current?.view;
    if (view) { cursorLineRef.current = view.state.doc.lineAt(view.state.selection.main.head).number; }
    if (isSplitView) syncService.current.syncContent(val, cursorLineRef.current);
  }, [handleContentUpdate, isSplitView]);

  // 3. Command & Event Distribution
  useEditorEvents({
    editorRef, liveContentRef, isSyncingRef, syncService, cursorLineRef,
    currentPath, isUnsaved, saveFile, openTab,
    setIsSplitView: setSplitView,
    setSaveAsDialogOpen: setSaveAsDialogOpen
  });

  // 4. Tab & Workspace Synchronization
  useEffect(() => { if (currentPath && fileName) openTab(currentPath, fileName); }, [currentPath, fileName, openTab]);
  useEffect(() => { if (currentPath && !currentPath.startsWith('untitled-')) selectPath(currentPath); }, [currentPath, selectPath]);
  useEffect(() => { if (currentPath) setTabDirty(currentPath, isUnsaved); }, [currentPath, isUnsaved, setTabDirty]);

  // 5. Atomic Reset (Critical Implementation)
  useEffect(() => {
    const normalize = (p: string | null) => p?.replace(/\\/g, '/').toLowerCase() || null;
    if (editorRef.current && initialContent !== undefined && currentPath !== prevPathRef.current && normalize(loadedPath) === normalize(currentPath)) {
      const savedCursor = currentPath ? getTabCursor(currentPath) : null;
      editorRef.current.resetState(initialContent, savedCursor?.cursorPosition, savedCursor?.scrollTop, savedCursor?.topLineNumber, savedCursor?.topOffset);
      prevPathRef.current = currentPath;
    }
  }, [initialContent, currentPath, getTabCursor, loadedPath]);

  // 6. External Interop (e.g., Image Preview)
  useEffect(() => {
    const handlePreview = (e: any) => setPreviewSrc(e.detail.src);
    window.addEventListener('preview-image-event', handlePreview);
    return () => window.removeEventListener('preview-image-event', handlePreview);
  }, []);

  return (
    <div className="flex-1 h-full bg-transparent flex flex-col min-w-0 min-h-0 overflow-hidden relative">
      <EditorKernelIntegration />
      {!isZenMode && <EditorTabs />}

      <EditorHeader isUnsaved={isUnsaved} />

      <EditorToolbar editorRef={editorRef} activeStates={activeStates} />

      <EditorMainView
        panels={panels} getEditorView={() => editorRef.current?.view ?? null}
        isSplitView={isSplitView} viewMode={viewMode} currentPath={currentPath}
        initialContent={initialContent} handleEditorUpdate={handleEditorUpdate}
        setActiveStates={setActiveStates} showSourceOnHover={true}
        headingNumbering={headingNumbering} editorRef={editorRef} previewEditorRef={previewEditorRef}
      />

      <EditorModals previewSrc={previewSrc} onClosePreview={() => setPreviewSrc(null)} editorRef={editorRef} />
    </div>
  );
}

import React, { useEffect, useRef, useCallback } from 'react';
import { X, ChevronUp, ChevronDown, Replace, ReplaceAll, CaseSensitive } from 'lucide-react';
import { EditorView } from '@codemirror/view';
import { useSearchController } from '../hooks/useSearchController';

interface SearchReplacePanelProps {
    getView: () => EditorView | null;
    onClose: () => void;
    isVisible: boolean;
}

export function SearchReplacePanel({ getView, onClose, isVisible }: SearchReplacePanelProps) {
    const searchInputRef = useRef<HTMLInputElement>(null);

    // [DECOUPLED] Delegate all logic to the controller hook
    const { state, actions } = useSearchController(getView, isVisible, onClose);

    const { searchTerm, replaceTerm, caseSensitive, matchCount, displayIndex, showReplace } = state;
    const { setSearchTerm, setReplaceTerm, setCaseSensitive, setShowReplace, next, prev, replace, replaceAll, close } = actions;

    // Focus management
    useEffect(() => {
        if (isVisible && searchInputRef.current) {
            requestAnimationFrame(() => {
                searchInputRef.current?.focus();
                searchInputRef.current?.select();
            });
        }
    }, [isVisible]);

    // Keyboard handling
    const handleKeyDown = useCallback((e: React.KeyboardEvent) => {
        if (e.key === 'Enter') {
            e.preventDefault(); e.stopPropagation();
            if (e.shiftKey) prev(); else next();
            requestAnimationFrame(() => searchInputRef.current?.focus());
        } else if (e.key === 'Escape') {
            e.preventDefault(); e.stopPropagation();
            close();
        }
    }, [next, prev, close]);

    const handleInputKeyDown = useCallback((e: React.KeyboardEvent) => {
        e.stopPropagation();
        if (e.key === 'Enter' || e.key === 'Escape') handleKeyDown(e);
    }, [handleKeyDown]);

    // Prevent button focus snatching
    const handleButtonMouseDown = useCallback((e: React.MouseEvent) => e.preventDefault(), []);

    if (!isVisible) return null;

    return (
        <div
            className="search-replace-panel absolute top-0 right-0 w-full bg-zinc-800 border-b border-zinc-700 px-4 py-2 flex flex-col gap-2 z-[100] select-none shadow-md"
            onKeyDown={handleKeyDown}
            onClick={(e) => e.stopPropagation()}
        >
            {/* Search Row */}
            <div className="flex items-center gap-2">
                <div className="flex-1 flex items-center gap-2">
                    <input
                        ref={searchInputRef}
                        type="text"
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        onKeyDown={handleInputKeyDown}
                        placeholder="查找..."
                        className="flex-1 bg-zinc-700 border border-zinc-600 rounded px-3 py-1.5 text-sm text-white placeholder-zinc-400 focus:outline-none focus:border-blue-500"
                        autoComplete="off"
                        spellCheck={false}
                    />
                    <span className="text-xs text-zinc-400 min-w-[60px]">
                        {matchCount > 0 ? `${displayIndex} / ${matchCount}` : '无匹配'}
                    </span>
                </div>

                <div className="flex items-center gap-1">
                    <button
                        type="button"
                        onClick={() => setCaseSensitive(!caseSensitive)}
                        onMouseDown={handleButtonMouseDown}
                        className={`p-1.5 rounded ${caseSensitive ? 'bg-blue-600 text-white' : 'text-zinc-400 hover:bg-zinc-700'}`}
                        title="区分大小写"
                    >
                        <CaseSensitive size={16} />
                    </button>
                    <button
                        type="button"
                        onClick={prev}
                        onMouseDown={handleButtonMouseDown}
                        disabled={matchCount === 0 || !searchTerm}
                        className="p-1.5 rounded text-zinc-400 hover:bg-zinc-700 disabled:opacity-50"
                        title="上一个 (Shift+Enter)"
                    >
                        <ChevronUp size={16} />
                    </button>
                    <button
                        type="button"
                        onClick={next}
                        onMouseDown={handleButtonMouseDown}
                        disabled={matchCount === 0 || !searchTerm}
                        className="p-1.5 rounded text-zinc-400 hover:bg-zinc-700 disabled:opacity-50"
                        title="下一个 (Enter)"
                    >
                        <ChevronDown size={16} />
                    </button>
                    <button
                        type="button"
                        onClick={() => setShowReplace(!showReplace)}
                        onMouseDown={handleButtonMouseDown}
                        className={`p-1.5 rounded ${showReplace ? 'bg-zinc-600 text-white' : 'text-zinc-400 hover:bg-zinc-700'}`}
                        title="替换"
                    >
                        <Replace size={16} />
                    </button>
                    <button
                        type="button"
                        onClick={close}
                        onMouseDown={handleButtonMouseDown}
                        className="p-1.5 rounded text-zinc-400 hover:bg-zinc-700"
                        title="关闭 (Esc)"
                    >
                        <X size={16} />
                    </button>
                </div>
            </div>

            {/* Replace Row */}
            {showReplace && (
                <div className="flex items-center gap-2">
                    <input
                        type="text"
                        value={replaceTerm}
                        onChange={(e) => setReplaceTerm(e.target.value)}
                        onKeyDown={handleInputKeyDown}
                        placeholder="替换为..."
                        className="flex-1 bg-zinc-700 border border-zinc-600 rounded px-3 py-1.5 text-sm text-white placeholder-zinc-400 focus:outline-none focus:border-blue-500"
                        autoComplete="off"
                        spellCheck={false}
                    />
                    <button
                        type="button"
                        onClick={replace}
                        onMouseDown={handleButtonMouseDown}
                        disabled={matchCount === 0 || !searchTerm}
                        className="px-3 py-1.5 rounded bg-zinc-700 text-zinc-300 text-sm hover:bg-zinc-600 disabled:opacity-50"
                    >
                        替换
                    </button>
                    <button
                        type="button"
                        onClick={replaceAll}
                        onMouseDown={handleButtonMouseDown}
                        disabled={matchCount === 0 || !searchTerm}
                        className="px-3 py-1.5 rounded bg-zinc-700 text-zinc-300 text-sm hover:bg-zinc-600 disabled:opacity-50"
                    >
                        全部替换
                    </button>
                </div>
            )}
        </div>
    );
}

export default SearchReplacePanel;

