import React from 'react';
import { useKernel } from '@/kernel/core/KernelContext';
import { useEditorStore } from '../../store/editorStore';
import { useEditorLogic } from '../../hooks/useEditorLogic';
import { EditorExportService } from '../../services/EditorExportService';
import { ImagePreview } from '@/shared/components/ui/ImagePreview';
import { SaveAsDialog } from '@/shared/components/ui/SaveAsDialog';

interface EditorModalsProps {
    previewSrc: string | null;
    onClosePreview: () => void;
    editorRef: any;
}

export const EditorModals: React.FC<EditorModalsProps> = ({
    previewSrc,
    onClosePreview,
    editorRef
}) => {
    const kernel = useKernel();
    const { currentPath, fileName } = useEditorLogic();
    const { saveAsDialogOpen, setSaveAsDialogOpen } = useEditorStore();
    const exportService = kernel.getService<EditorExportService>('editorExportService');

    return (
        <>
