                        if (savePath) {
                            await exportService.exportFile(content, savePath, format, {
                                basePath: currentPath ? await fileSystem.getDirname(currentPath) : undefined
                            });
                        }
                    }
                }}
            />
        </>
    );
};

import { keymap } from '@codemirror/view';
import { Prec } from '@codemirror/state';
import { syntaxTree } from "@codemirror/language";
import { indentMore } from "@codemirror/commands";

export const createEditorKeymap = () => {
    // 使用 Prec.highest 确保我们的键位映射优先级最高，覆盖 CodeMirror 或浏览器的默认行为
    return Prec.highest(keymap.of([
        // === 1. Tab 键处理 ===
        {
            key: "Tab",
            run: (view) => {
                const { state, dispatch } = view;
                const { from, to, empty } = state.selection.main;

                if (empty) {
                    // 光标向后移动 1 位
                    dispatch({
                        changes: { from, insert: "\t" },
                        selection: { anchor: from + 1 }
                    });
                } else {
                    // 有选区时：执行整块缩进
                    indentMore(view);
                }
                // 返回 true 表示拦截此事件，防止焦点跳出编辑器 (浏览器默认行为)
                return true;
            },
            preventDefault: true // 显式阻止默认行为
        },

        // === 2. Enter 键处理 ===
        {
            key: "Enter",
            run: (view) => {
                const { state, dispatch } = view;
                const { from, to } = state.selection.main;
                // 如果有选区，交给默认行为（通常是删除选区并换行）
                if (from !== to) return false;

                const line = state.doc.lineAt(from);
                const text = line.text;
                const trimText = text.trim();

                // 2.1 引用与列表的智能退出
                // 如果当前行只有标记符（如 "> ", "- ", "1. "），再次按回车则删除标记符，变为空行
                if (/^>\s*$/.test(text) || /^[-*]\s*$/.test(text) || /^\d+\.\s*$/.test(text)) {
                    dispatch({
                        changes: { from: line.from, to: line.to, insert: "" }
                    });
                    return true;
                }

                // 2.2 代码块自动闭合 (Smart Auto-Close)
                // 匹配以 ``` 开头的行 (例如 ```, ```js, ```python)
                if (/^\s*```/.test(trimText)) {
                    const tree = syntaxTree(state);
                    const node = tree.resolveInner(from, -1);

                    // 检查下一行是否已经是闭合符 (防止重复插入)
                    let nextLineIsClosing = false;
                    if (line.number < state.doc.lines) {
                        const nextLine = state.doc.line(line.number + 1);
                        if (/^\s*```/.test(nextLine.text)) {
                            nextLineIsClosing = true;
                        }
                    }

                    // 如果下一行不是闭合符，则自动插入闭合结构
                    // 逻辑：换行 + 光标位 + 换行 + 闭合符
                    if (!nextLineIsClosing) {
                        dispatch({
                            changes: { from: line.to, insert: "\n\n```" },
                            selection: { anchor: line.to + 1 } // 将光标定位到中间的空行
                        });
                        return true;
                    }
                }

                // 2.3 公式块自动闭合
                // 匹配 $$
                if (trimText === "$$") {
                    const tree = syntaxTree(state);
                    const node = tree.resolveInner(from, -1);
                    // 如果光标已经在一个 MathBlock 内部，则允许默认换行，不重复闭合
                    if (node.name.includes("Math")) return false;

                    dispatch({
                        changes: { from: line.from, to: line.to, insert: "$$\n\n$$" },
                        selection: { anchor: line.from + 3 }
                    });
                    return true;
                }

                return false; // 其他情况交给 CodeMirror 默认处理
            }
        },

        // === 3. ArrowDown 键 (代码块强制跳出) ===
        {
            key: "ArrowDown",
            run: (view) => {
                const { state, dispatch } = view;
                const head = state.selection.main.head;
                const line = state.doc.lineAt(head);

                const tree = syntaxTree(state);
                const node = tree.resolveInner(head, -1);

                // 判断当前是否在代码块或公式块内
                const isBlock = node.name.includes("Code") || node.name.includes("Math");

                // 判断当前行是否是闭合符号行 (``` 或 $$)
                const isClosingFence = /^\s*```/.test(line.text) || /^\s*\$\$/.test(line.text);

                // 只有在 块内 且是 闭合行 时触发跳出逻辑
                if (isBlock && isClosingFence) {
                    if (line.number === state.doc.lines) {
                        // 情况 A: 文档最后一行 -> 必须插入新行才能跳出
                        dispatch({
                            changes: { from: line.to, insert: "\n" },
                            selection: { anchor: line.to + 1 }
                        });
                        // 滚动到底部确保可见
                        setTimeout(() => {
                            view.scrollDOM.scrollTo({ top: view.scrollDOM.scrollHeight, behavior: 'smooth' });
                        }, 10);
                    } else {
                        // 情况 B: 不是最后一行 -> 强制光标移动到下一行开头
                        const nextLine = state.doc.line(line.number + 1);
                        dispatch({ selection: { anchor: nextLine.from } });
                    }
                    return true;
                }
                return false;
            }
        },

        // === 4. Backspace 键 (智能删除) ===
        {
            key: "Backspace",
            run: (view) => {
                const { state, dispatch } = view;
                const { from, empty } = state.selection.main;
                if (!empty) return false;

                const line = state.doc.lineAt(from);
                // 解决：引用块删除残留
                // 如果当前行只有 "> " 且光标在末尾，按退格键直接清空整行，而不是只删一个空格
                if (line.text === "> " && from === line.to) {
                    dispatch({ changes: { from: line.from, to: line.to, insert: "" } });
                    return true;
                }
                return false;
            }
        },

        // === 5. 禁用内置搜索快捷键 (因为使用了自定义搜索面板) ===
        { key: "Mod-f", run: () => true },
        { key: "Mod-h", run: () => true },
        { key: "Mod-g", run: () => true },
        { key: "Shift-Mod-g", run: () => true },
        { key: "Mod-Alt-f", run: () => true }
    ]));
};

import { EditorView } from '@codemirror/view';
import { Extension } from '@codemirror/state';
import { HighlightStyle, syntaxHighlighting } from '@codemirror/language';
import { tags as t } from '@lezer/highlight';

/**
 * 创建动态主题适配器
 * 
 * 核心逻辑：
 * 1. 设置编辑器主背景为 transparent，让底层 CSS 背景透上来
 * 2. 使用 var(--foreground) 等 CSS 变量配置基础颜色
 * 3. 这里的 syntaxHighlighting 仍然使用 JS 定义的颜色，但可以微调以适应 CSS 变量
 */
export const createDynamicTheme = (isDark: boolean): Extension[] => {

    // 基础编辑器样式（布局、背景、光标）
    const theme = EditorView.theme({
        "&": {
            color: "hsl(var(--foreground))",
            backgroundColor: "transparent", // 关键：透明背景
        },
        ".cm-content": {
            caretColor: "hsl(var(--primary))",
            fontFamily: "var(--font-family, 'Segoe UI', system-ui, sans-serif)",
        },
        "&.cm-focused .cm-cursor": {
            borderLeftColor: "hsl(var(--primary))"
        },
        "&.cm-focused .cm-selectionBackground, ::selection": {
            backgroundColor: "hsla(var(--primary), 0.2)", // 使用系统主色调，加透明度
        },
        ".cm-gutters": {
            backgroundColor: "transparent", // 行号区域透明
            color: "hsl(var(--muted-foreground))", // 行号颜色
            borderRight: "1px solid transparent", // 去除分割线，显得更现代
        },
        ".cm-activeLineGutter": {
            backgroundColor: "hsla(var(--muted), 0.4)",
            color: "hsl(var(--foreground))",
        },
        ".cm-activeLine": {
            backgroundColor: "hsla(var(--muted), 0.2)", // 当前行高亮
        },

        // 搜索匹配高亮
        ".cm-searchMatch": {
            backgroundColor: "hsla(var(--accent), 0.5)",
            outline: "1px solid hsl(var(--accent))"
        },
        ".cm-searchMatch.cm-searchMatch-selected": {
            backgroundColor: "hsl(var(--accent))",
            color: "hsl(var(--accent-foreground))"
        }
    }, { dark: isDark });

    // 语法高亮 (Syntax Highlighting)
    // 这里我们定义一套通用的高亮规则，尽量使用 CSS 变量或硬编码的通用色
    // 如果需要完全跟随主题，这里的工作量会非常大（需要映射所有 tag 到 variable）。
    // 作为折衷，我们使用一套较为中性的高亮方案，或者根据 isDark 分别返回 githubLight/oneDark 的高亮部分

    // 简单起见，我们暂时手动定义一个中性高亮，或者直接沿用外部传入的 highlightStyle
    // 但为了演示“动态性”，我们这里定义一个基于变量的简单高亮（可选）
    // 目前 CodeMirrorEditor 还是会传入 basicSetup，里面可能包含 highlight。
    // 我们主要负责把“容器”变透明。

    return [theme];
};

import { EditorView } from "@codemirror/view";
import { EditorState } from "@codemirror/state";

export type EditorCommand =
  | 'BOLD' | 'ITALIC' | 'STRIKE' | 'CODE'
  | 'H1' | 'H2' | 'H3'
  | 'UL' | 'OL' | 'TASK' | 'QUOTE'
  | 'LINK' | 'IMAGE' | 'TABLE' | 'UNDO' | 'REDO';

export interface IEditorRef {
  getContent: () => string;
  setContent: (content: string) => void;
  getScrollState: () => { cursorPosition: number; scrollTop: number; topLineNumber: number; topOffset: number };
  resetState: (content: string, cursorPosition?: number, scrollTop?: number, topLineNumber?: number, topOffset?: number) => void;
  // 新增：插入图片接口
  insertImage: (file: File) => Promise<void>;
  executeCommand: (cmd: EditorCommand, params?: any) => void;
  getActiveStates: () => Record<string, boolean>;
  view?: EditorView;
}

export interface IPluginContext {
  kernel: any;
  registerCommand: (id: string, handler: (...args: any[]) => void) => void;
  registerEditorExtension: (ext: any) => void;
  registerEditorHeaderItem: (id: string, component: React.ComponentType<any>) => void;
  registerSidebarItem: (id: string, component: React.ComponentType<any>, label?: string, icon?: any) => void;
  registerService: (id: string, service: any) => void;
}

/**
 * useCursorSync.ts
 * 
 * 提取自 NoteEditor.tsx 的光标和滚动位置同步逻辑。
 * 处理标签页切换时保存/恢复光标位置。
 */

import { useCallback, useLayoutEffect } from 'react';
import { useKernel } from '@/kernel/core/KernelContext';
import { useKernelEvent } from '@/kernel/hooks/useKernelEvent';
import { useEditorTabsStore } from '../stores/editorTabsStore';
import { IEditorRef } from '../framework/types';
import { EditorView } from '@codemirror/view';

interface UseCursorSyncOptions {
    editorRef: React.RefObject<IEditorRef | null>;
    currentPath: string | null;
}

export function useCursorSync({
    editorRef,
    currentPath,
}: UseCursorSyncOptions) {
    const kernel = useKernel();
    const { setTabCursor, getTabCursor } = useEditorTabsStore();

    // 保存光标位置到标签页状态
    const saveCursor = useCallback((filePath: string) => {
        if (editorRef.current && editorRef.current.getScrollState) {
            const state = editorRef.current.getScrollState();
            setTabCursor(filePath, state.cursorPosition, state.scrollTop, state.topLineNumber, state.topOffset);
        }
    }, [editorRef, setTabCursor]);

    // 恢复光标位置
    const restoreCursor = useCallback((filePath: string) => {
        const cursor = getTabCursor(filePath);
        if (cursor && editorRef.current) {
            // 注意：这里通常由 NoteEditor 在加载内容时调用 resetState。
        }
    }, [editorRef, getTabCursor]);

    // [NEW] 核心时序修复：使用 useLayoutEffect 的清理函数确保在路径切换或卸载前瞬间保存
    // 这比监听外部 REQUEST_SAVE_CURSOR 更加及时且同步
    useLayoutEffect(() => {
        return () => {
            if (currentPath) {
                saveCursor(currentPath);
            }
        };
    }, [currentPath, saveCursor]);

    // 监听文件切换前的保存事件
    useKernelEvent('REQUEST_SAVE_CURSOR', (filePath) => {
        saveCursor(filePath);
    });

    return {
        saveCursor,
        restoreCursor,
    };
}

import { useEffect } from 'react';
import { useKernelEvent } from '@/kernel/hooks/useKernelEvent';
import { IEditorRef } from '../framework/types';
import { EditorSyncService } from '../services/EditorSyncService';

interface UseEditorEventsProps {
    editorRef: React.MutableRefObject<IEditorRef | null>;
    liveContentRef: React.MutableRefObject<string>;
    isSyncingRef: React.MutableRefObject<boolean>;
    syncService: React.MutableRefObject<EditorSyncService>;
    cursorLineRef: React.MutableRefObject<number>;
    currentPath: string | null;
    isUnsaved: boolean;
    saveFile: () => void;
    openTab: (id: string, title: string) => void;
    setIsSplitView: (val: boolean) => void;
    setSaveAsDialogOpen: (val: boolean) => void;
}

export function useEditorEvents({
    editorRef,
    liveContentRef,
    isSyncingRef,
    syncService,
    cursorLineRef,
    currentPath,
    isUnsaved,
    saveFile,
    openTab,
    setIsSplitView,
    setSaveAsDialogOpen
}: UseEditorEventsProps) {
    // 1. 监听内容同步（如图片路径替换后）
    useKernelEvent('SYNC_EDITOR_CONTENT', (data: { replacements: any[]; savedContent: string }) => {
        if (!editorRef.current?.view) return;
        const view = editorRef.current.view;
        const { replacements, savedContent } = data;

        isSyncingRef.current = true;
        const scrollTop = view.scrollDOM.scrollTop;

        const changes: { from: number; to: number; insert: string }[] = [];
        const docText = view.state.doc.toString();

        for (const { oldText, newText } of replacements) {
            let searchFrom = 0;
            while (true) {
                const idx = docText.indexOf(oldText, searchFrom);
                if (idx === -1) break;
                changes.push({ from: idx, to: idx + oldText.length, insert: newText });
                searchFrom = idx + oldText.length;
            }
        }

        if (changes.length > 0) {
            changes.sort((a, b) => b.from - a.from);
            view.dispatch({ changes });
        }

        liveContentRef.current = savedContent;

        requestAnimationFrame(() => {
            view.scrollDOM.scrollTop = scrollTop;
            setTimeout(() => { isSyncingRef.current = false; }, 100);
        });
    });

    // 2. 监听文本插入
    useKernelEvent('EDITOR_INSERT_TEXT', (text: string) => {
        const view = editorRef.current?.view;
        if (!view) return;
        const { from, to } = view.state.selection.main;
        view.dispatch({
            changes: { from, to, insert: text },
            selection: { anchor: from + text.length }
        });
        view.focus();
    });

    // 3. 基础指令处理
    useKernelEvent('APP_CMD_SAVE', () => saveFile());
    useKernelEvent('SAVE_ALL_FILES', () => { if (isUnsaved) saveFile(); });
    useKernelEvent('EDITOR_FOCUS', () => { editorRef.current?.view?.focus(); });
    useKernelEvent('CREATE_UNTITLED_TAB', () => {
        openTab(`untitled-${Date.now()}`, 'Untitled');
    });
    useKernelEvent('APP_CMD_SAVE_AS', () => setSaveAsDialogOpen(true));

    // 4. 分栏控制
    useKernelEvent('SPLIT_VIEW_TAB', () => {
        setIsSplitView(true);
        requestAnimationFrame(() => {
            syncService.current.syncContent(liveContentRef.current, cursorLineRef.current, true);
        });
    });
    useKernelEvent('CLOSE_SPLIT_VIEW', () => setIsSplitView(false));
}

/**
 * useEditorExport.ts
 * 
 * 提取自 NoteEditor.tsx 的导出相关逻辑。
 * 处理 PDF 和 Word (MHTML) 导出功能。
 */

import { useCallback } from 'react';
import { useKernel } from '@/kernel/core/KernelContext';
import { useKernelEvent } from '@/kernel/hooks/useKernelEvent';
import { IEditorRef } from '../framework/types';

interface UseEditorExportOptions {
    editorRef: React.RefObject<IEditorRef | null>;
    fileName: string | undefined;
    currentPath: string | null;
}

export function useEditorExport({
    editorRef,
    fileName,
    currentPath,
}: UseEditorExportOptions) {
    const kernel = useKernel();

    const handleExport = useCallback(async (type: 'pdf' | 'word', args?: any) => {
        // 如果有参数（说明是侧边栏传来的多文件/指定文件），则忽略，由全局 Handler 处理
        if (args && (Array.isArray(args) || args.length > 0)) return;

        if (!editorRef.current) return;
        const content = editorRef.current.getContent(); // 获取最新内容(含未保存)
        if (!content) return;

        try {
            const markdownService = kernel.getService<any>('markdownService');
            const DOMPurify = (await import('dompurify')).default;

            const rawHtml = await markdownService.render(content);
            const cleanHtml = DOMPurify.sanitize(rawHtml as string);

            const defaultName = fileName ? fileName.replace(/\.md$/i, '') : 'Untitled';
            const ext = type === 'pdf' ? 'pdf' : 'mht';
            const filterName = type === 'pdf' ? 'PDF' : 'Word (MHTML)';

            const savePath = await kernel.getService<any>('fileSystem').showSaveDialog({
                defaultPath: `${defaultName}.${ext}`,
                filters: [{ name: filterName, extensions: [ext] }]
            });

            if (savePath) {
                // 获取当前文件的基础路径用于解析相对图片
                const basePath = currentPath
                    ? await kernel.getService<any>('fileSystem').getDirname(currentPath)
                    : undefined;

                if (type === 'pdf') {
                    await kernel.getService<any>('fileSystem').exportToPDF(cleanHtml, savePath, { basePath });
                } else {
                    await kernel.getService<any>('fileSystem').exportToWord(cleanHtml, savePath, { basePath });
                }
            }
        } catch (e) {
            console.error("Export failed:", e);
        }
    }, [editorRef, fileName, currentPath, kernel]);

    // 订阅导出事件
    // 订阅导出事件
    useKernelEvent('APP_CMD_EXPORT_PDF', (args) => handleExport('pdf', args));
    useKernelEvent('APP_CMD_EXPORT_WORD', (args) => handleExport('word', args));

    return { handleExport };
}

/**
 * useEditorKeyboard.ts
 * 
 * 提取自 NoteEditor.tsx 的键盘快捷键处理逻辑。
 * 处理 Ctrl+S (保存), Ctrl+Shift+S (另存为), Ctrl+F (查找), ESC (关闭面板) 等快捷键。
 */

import { useEffect, useCallback, useState } from 'react';

interface UseEditorKeyboardOptions {
    saveFile: () => void;
    onSaveAs: () => void;
}

interface UseEditorKeyboardResult {
    showSearchPanel: boolean;
    toggleSearchPanel: () => void;
    closeSearchPanel: () => void;
}

export function useEditorKeyboard({
    saveFile,
    onSaveAs,
}: UseEditorKeyboardOptions): UseEditorKeyboardResult {
    const [showSearchPanel, setShowSearchPanel] = useState(false);

    const toggleSearchPanel = useCallback(() => {
        setShowSearchPanel(prev => !prev);
    }, []);

    const closeSearchPanel = useCallback(() => {
        setShowSearchPanel(false);
    }, []);

    // Ctrl+F / ESC 处理
    useEffect(() => {
        const handleKeyDown = (e: KeyboardEvent) => {
            const isCtrl = e.ctrlKey || e.metaKey;

            // Ctrl+F: 打开/聚焦查找面板
            if (isCtrl && e.key.toLowerCase() === 'f') {
                e.preventDefault();
                e.stopPropagation();
                toggleSearchPanel();
                return;
            }

            // ESC: 关闭查找面板（仅当面板打开时）
            if (e.key === 'Escape' && showSearchPanel) {
                e.preventDefault();
                e.stopPropagation();
                closeSearchPanel();
            }
        };

        window.addEventListener('keydown', handleKeyDown, true); // capture phase
        return () => window.removeEventListener('keydown', handleKeyDown, true);
    }, [showSearchPanel, toggleSearchPanel, closeSearchPanel]);

    // 注意：Ctrl+S / Ctrl+Shift+S 的处理已移至 AppLayout.tsx 全局监听，
    // 以避免重复触发导致的另存为对话框异常行为。

    return {
        showSearchPanel,
        toggleSearchPanel,
        closeSearchPanel,
    };
}

import { useState, useEffect, useCallback, useRef } from 'react';
import { useKernel } from '@/kernel/core/KernelContext';
import { useEditorStore } from '../store/editorStore';
import { useGlobalStore } from '@/shared/stores/globalStore';
import { useEditorTabsStore } from '../stores/editorTabsStore';
import { IFileSystem } from '@/kernel/interfaces/IFileSystem';

export function useEditorLogic() {
  const kernel = useKernel();
  const fileSystem = kernel.getService<IFileSystem>('fileSystem');

  // Store
  const filePath = useEditorStore((state) => state.currentFileId);
  const setCurrentFile = useEditorStore((state) => state.setCurrentFile);
  const setIsUnsavedStore = useEditorStore((state) => state.setUnsaved);
  const isUnsavedStore = useEditorStore((state) => state.isUnsaved);
  const { autoSaveIntervalMinutes, getAutoSaveIntervalMs } = useGlobalStore();

  // Tab Store - 用于内容缓存
  const { updateTabContent, getTabContent, getTab, clearTabContent, setTabDirty, setTabCursor } = useEditorTabsStore();

  const contentRef = useRef<string>('');
  const [initialContent, setInitialContent] = useState<string>('');
  const activePathRef = useRef<string | null>(null);
  const isUnsavedRef = useRef(false);
  const statusRef = useRef<'idle' | 'switching'>('idle');
  const saveTimeoutRef = useRef<NodeJS.Timeout | null>(null);

  const skipNextLoadRef = useRef(false);

  useEffect(() => {
    isUnsavedRef.current = isUnsavedStore;
  }, [isUnsavedStore]);

  useEffect(() => {
    if (filePath && !activePathRef.current) activePathRef.current = filePath;
  }, []);

  // === 统一保存逻辑 ===
  // 返回 savedContent 和 replacements 数组，用于精准替换编辑器内容
  interface Replacement { oldText: string; newText: string; }
  const processContentAndSave = async (targetPath: string, content: string): Promise<{ savedContent: string; replacements: Replacement[] }> => {
    let processedContent = content;
    const replacements: Replacement[] = [];
    const saveDir = await fileSystem.getDirname(targetPath);
    const assetsDir = await fileSystem.pathJoin(saveDir, 'assets');

    const tempImgRegex = /!\[(.*?)\]\(local-resource:\/\/\/(.*?temp_images.*?)\)/g;
    const matches = [...processedContent.matchAll(tempImgRegex)];

    if (matches.length > 0) {
      for (const match of matches) {
        const fullMatch = match[0];
        const altText = match[1];
        const srcPath = match[2];

        const fileName = srcPath.split(/[\\/]/).pop() || `img_${Date.now()}.png`;
        const destPath = await fileSystem.pathJoin(assetsDir, fileName);

        // 使用 copy 而非 move，保留原文件以支持撤销操作
        // temp_images 目录的清理应在应用退出时进行
        try {
          const copyRes = await fileSystem.copy(srcPath, destPath);
          if (copyRes.success) {
            const newText = `![${altText}](assets/${fileName})`;
            processedContent = processedContent.split(fullMatch).join(newText);
            // 记录替换，用于精准更新编辑器
            replacements.push({ oldText: fullMatch, newText });
          } else {
            console.warn(`Image copy failed: ${srcPath} -> ${destPath}`, copyRes.error);
          }
        } catch (err) {
          console.error(`Image copy error: ${srcPath}`, err);
          // 继续处理其他图片，不阻塞保存
        }
      }
    }

    await fileSystem.saveFile(targetPath, processedContent);
    return { savedContent: processedContent, replacements };
  };

  // === 文件切换 ===
  // 追踪当前 initialContent 对应的路径，用于防止 stale content
  const [loadedPath, setLoadedPath] = useState<string | null>(null);

  // === 文件切换 ===
  useEffect(() => {
    if (!fileSystem) return;

    const switchFile = async () => {
      const prevPath = activePathRef.current;
      const nextPath = filePath;

      // 路径规范化比较，处理 Windows 反斜杠问题
      const normalizePath = (p: string | null) => p?.replace(/\\/g, '/') || null;
      const normalizedPrev = normalizePath(prevPath);
      const normalizedNext = normalizePath(nextPath);

      if (skipNextLoadRef.current && normalizedNext === normalizedPrev) {
        skipNextLoadRef.current = false;
        statusRef.current = 'idle';
        return;
      }

      // 如果是同一个文件，不重新加载（防止点击标签页时清除未保存状态）
      if (normalizedPrev === normalizedNext && !skipNextLoadRef.current) return;

      statusRef.current = 'switching';

      // === 切换前保存光标位置 ===
      if (prevPath) {
        // 请求 NoteEditor 报告当前光标位置
        kernel.emit('REQUEST_SAVE_CURSOR', prevPath);
      }

      // === 切换前缓存当前内容到 Tab Store ===
      if (prevPath && isUnsavedRef.current) {
        // 将当前未保存的内容缓存到 tab store
        updateTabContent(prevPath, contentRef.current);

        // 同时尝试自动保存到磁盘（如果启用）
        const autoSaveMs = getAutoSaveIntervalMs();
        if (autoSaveMs > 0 && !prevPath.startsWith('untitled-')) {
          try {
            await processContentAndSave(prevPath, contentRef.current);
            // 保存成功后清除缓存，标记为已保存
            clearTabContent(prevPath);
          } catch (e) {
            console.error(`Auto-Saving failed:`, e);
          }
        }
      }

      activePathRef.current = nextPath;

      if (!nextPath) {
        setInitialContent('');
        contentRef.current = '';
        setLoadedPath(null); // Clear loaded path
        setIsUnsavedStore(false);
        isUnsavedRef.current = false;
        statusRef.current = 'idle';
        return;
      }

      // === 优先从 Tab Cache 读取内容 ===
      const cachedContent = getTabContent(nextPath);
      const tab = getTab(nextPath);

      if (cachedContent !== undefined && tab?.isDirty) {
        // 有缓存的未保存内容，使用缓存
        contentRef.current = cachedContent;
        setInitialContent(cachedContent);
        setLoadedPath(nextPath); // Mark loaded
        setIsUnsavedStore(true);
        isUnsavedRef.current = true;
        setTimeout(() => { statusRef.current = 'idle'; }, 50);
        return;
      }

      // === 支持 Untitled 虚拟文件 ===
      if (nextPath.startsWith('untitled-')) {
        // 从缓存读取或使用空内容
        const untitledContent = cachedContent || '';
        contentRef.current = untitledContent;
        setInitialContent(untitledContent);
        setLoadedPath(nextPath); // Mark loaded
        const hasContent = untitledContent.length > 0;
        setIsUnsavedStore(hasContent);
        isUnsavedRef.current = hasContent;
        setTimeout(() => { statusRef.current = 'idle'; }, 50);
        return;
      }

      // 从磁盘读取
      try {
        const res = await fileSystem.readFile(nextPath);
        if (res.success && typeof res.content === 'string') {
          contentRef.current = res.content;
          setInitialContent(res.content);
          setLoadedPath(nextPath); // Mark loaded
          setIsUnsavedStore(false);
          isUnsavedRef.current = false;
        }
      } catch (err) { console.error('Read Error:', err); }
      finally { setTimeout(() => { statusRef.current = 'idle'; }, 50); }
    };

    switchFile();
  }, [filePath, fileSystem, updateTabContent, getTabContent, getTab, clearTabContent, kernel]);

  // ... (handleContentUpdate logic unchanged) ... (omitted for brevity, assume tool keeps unchanged lines if not targeted)
  // Actually, I need to be careful with replace_file_content for large blocks.
  // I will target the end of the file to return loadedPath.

  // Wait, I can't just replace the middle without potentially breaking the hook return if I don't see the bottom.
  // I see the bottom in the viewed file (lines 273-282).

  // Let me replace the entire logical block of switchFile to include setLoadedPath calls.

  // ... (skip) ...

  // I'll assume I can just target the return statement to add loadedPath, and the state declaration at the top.
  // Since I need to modify `switchFile` logic which is huge, I'll do it carefully 

  // STRATEGY: 
  // 1. Add `loadedPath` state near the top.
  // 2. Modify `switchFile` to call `setLoadedPath`.
  // 3. Update return object.

  // Multi-replace is best here.


  const debouncedSyncRef = useRef<NodeJS.Timeout | null>(null);

  const handleContentUpdate = useCallback((newVal: string) => {
    if (statusRef.current === 'switching') return;
    contentRef.current = newVal;

    // === 修复内容窜台：在设置定时器前捕获当前路径 ===
    const currentPath = activePathRef.current;
    if (debouncedSyncRef.current) clearTimeout(debouncedSyncRef.current);
    debouncedSyncRef.current = setTimeout(() => {
      // 使用捕获的 currentPath，而非执行时的 activePathRef.current
      if (currentPath && statusRef.current === 'idle') {
        updateTabContent(currentPath, newVal);
      }
    }, 500);

    if (!isUnsavedRef.current) {
      setIsUnsavedStore(true);
      isUnsavedRef.current = true;
    }
  }, [setIsUnsavedStore, updateTabContent]);


  const saveFile = useCallback(async () => {
    const path = activePathRef.current;
    if (!path || path.startsWith('untitled-')) return saveAs();

    try {
      const { savedContent, replacements } = await processContentAndSave(path, contentRef.current);

      // 如果内容被修改（图片路径替换），需要同步更新编辑器
      if (replacements.length > 0) {
        contentRef.current = savedContent;
        // 使用事件通知编辑器进行精准替换，而不是全量替换
        // 这避免了光标跳动、滚动跳转和 Widget 重建问题
        kernel.emit('SYNC_EDITOR_CONTENT', { replacements, savedContent });
      }

      setIsUnsavedStore(false);
      isUnsavedRef.current = false;

      // 清除 tab 缓存，因为已保存
      clearTabContent(path);
    } catch (e) { console.error(e); }
  }, [fileSystem, setIsUnsavedStore, kernel, clearTabContent]);

  const saveAs = useCallback(async () => {
    if (!fileSystem) return;
    try {
      // 如果是 untitled，默认名设为 Untitled.md
      let defaultName = 'Untitled.md';
      if (activePathRef.current && !activePathRef.current.startsWith('untitled-')) {
        defaultName = activePathRef.current.split(/[/\\]/).pop() || 'Untitled.md';
      }

      const savePath = await fileSystem.showSaveDialog({ defaultPath: defaultName });

      if (savePath) {
        const { savedContent } = await processContentAndSave(savePath, contentRef.current);
        contentRef.current = savedContent;
        setInitialContent(savedContent);

        activePathRef.current = savePath;
        setIsUnsavedStore(false);
        isUnsavedRef.current = false;

        skipNextLoadRef.current = true;
        setCurrentFile(savePath);
      }
    } catch (e) {
      console.error("SaveAs failed:", e);
    } finally {
      statusRef.current = 'idle';
    }
  }, [fileSystem, setIsUnsavedStore, setCurrentFile]);

  // 自动保存
  useEffect(() => {
    if (saveTimeoutRef.current) clearTimeout(saveTimeoutRef.current);
    const autoSaveMs = getAutoSaveIntervalMs();
    if (autoSaveMs <= 0) return;
    if (isUnsavedStore && activePathRef.current && statusRef.current === 'idle') {
      saveTimeoutRef.current = setTimeout(() => { saveFile(); }, autoSaveMs);
    }
    return () => { if (saveTimeoutRef.current) clearTimeout(saveTimeoutRef.current); };
  }, [contentRef.current, isUnsavedStore, autoSaveIntervalMinutes, saveFile, getAutoSaveIntervalMs]);

  return {
    currentPath: filePath,
    initialContent,
    isUnsaved: isUnsavedStore,
    handleContentUpdate,
    saveFile,
    saveAs,
    fileName: filePath ? filePath.split(/[/\\]/).pop() : 'Untitled',
    isLoading: statusRef.current === 'switching',
    loadedPath // Expose loadedPath for synchronization
  };
}

import { useCallback } from 'react';
import { EditorView } from '@codemirror/view';
import { useService } from '@/kernel/core/KernelContext';
import { IFileSystem } from '@/kernel/interfaces/IFileSystem';

/**
 * 编辑器媒体资源处理 Hook
 * 负责图片插入、粘贴处理等与文件系统交互的操作
 */
export function useEditorMedia(basePath: string | null) {
    const fileSystem = useService<IFileSystem>('fileSystem');

    const insertImage = useCallback(async (view: EditorView, file: File) => {
        if (!view || !fileSystem) return;

        let insertPath = '';
        const filePath = (file as any).path;

        if (filePath) {
            if (basePath) {
                const fileDir = await fileSystem.getDirname(filePath);
                const normFileDir = fileDir.replace(/\\/g, '/').toLowerCase();
                const normBasePath = basePath.replace(/\\/g, '/').toLowerCase();

                if (normFileDir === normBasePath) {
                    insertPath = file.name;
                } else {
                    const cleanPath = filePath.replace(/\\/g, '/');
                    insertPath = `local-resource:///${cleanPath}`;
                }
            } else {
                const cleanPath = filePath.replace(/\\/g, '/');
                insertPath = `local-resource:///${cleanPath}`;
            }
        } else {
            const buffer = await file.arrayBuffer();
            const ext = file.name.split('.').pop() || 'png';
            const fileName = `img_${Date.now()}.${ext}`;
            const res = await fileSystem.saveTempImage(buffer, fileName);
            if (res.success && res.path) {
                const cleanPath = res.path.replace(/\\/g, '/');
                insertPath = `local-resource:///${cleanPath}`;
            }
        }

        if (insertPath) {
            const { from } = view.state.selection.main;
            const insertText = `![image](${insertPath})`;
            view.dispatch({
                changes: { from, insert: insertText },
                selection: { anchor: from + insertText.length }
            });
            view.focus();
        }
    }, [basePath, fileSystem]);

    const handlePaste = useCallback(async (event: ClipboardEvent, view: EditorView) => {
        const items = event.clipboardData?.items;
        if (!items) return;
        for (const item of items) {
            if (item.type.indexOf('image') !== -1) {
                event.preventDefault();
                const file = item.getAsFile();
                if (file) await insertImage(view, file);
            }
        }
    }, [insertImage]);

    return {
        insertImage,
        handlePaste
    };
}

