import { useState, useCallback, useRef, useEffect } from 'react';
import { EditorView } from '@codemirror/view';
import { EditorSearchService } from '../services/EditorSearchService';

/**
 * 搜索控制器 Hook
 * 封装搜索状态管理、防抖逻辑以及高层操作
 */
export function useSearchController(getView: () => EditorView | null, isVisible: boolean, onClose: () => void) {
    const [searchTerm, setSearchTerm] = useState('');
    const [replaceTerm, setReplaceTerm] = useState('');
    const [caseSensitive, setCaseSensitive] = useState(false);
    const [matchCount, setMatchCount] = useState(0);
    const [currentIndex, setCurrentIndex] = useState(0);
    const [showReplace, setShowReplace] = useState(false);

    const matchesRef = useRef<{ from: number, to: number }[]>([]);
    const searchDebounceRef = useRef<NodeJS.Timeout | null>(null);

    // 执行核心搜索逻辑
    const performSearch = useCallback((term: string, caseSens: boolean) => {
        const view = getView();
        if (!view) return;

        const matches = EditorSearchService.findMatches(view, term, caseSens);
        matchesRef.current = matches;
        setMatchCount(matches.length);
        setCurrentIndex(0);

        // 搜索时不跳转，仅高亮
        // EditorSearchService.findMatches 已负责 dispatch setSearchQuery
    }, [getView]);

    // 面板可见性切换清理
    useEffect(() => {
        if (!isVisible) {
            const view = getView();
            if (view) EditorSearchService.clearSearch(view);
            matchesRef.current = [];
            setMatchCount(0);
            setCurrentIndex(0);
        } else if (searchTerm) {
            // 重新打开时恢复搜索
            performSearch(searchTerm, caseSensitive);
        }
    }, [isVisible, getView, searchTerm, caseSensitive, performSearch]);

    // 搜索词变更 (带防抖)
    const handleSearchChange = useCallback((value: string) => {
        setSearchTerm(value);
        if (searchDebounceRef.current) clearTimeout(searchDebounceRef.current);
        searchDebounceRef.current = setTimeout(() => performSearch(value, caseSensitive), 150);
    }, [caseSensitive, performSearch]);

    // 导航逻辑
    const navigate = useCallback((direction: 'next' | 'prev') => {
        const view = getView();
        const matches = matchesRef.current;
        if (!view || matches.length === 0) return;

        let nextIdx = direction === 'next'
            ? (currentIndex + 1) % matches.length
            : (currentIndex - 1 + matches.length) % matches.length;

        setCurrentIndex(nextIdx);
        EditorSearchService.jumpToMatch(view, matches[nextIdx]);
    }, [getView, currentIndex]);

    // 替换逻辑
    const handleReplace = useCallback(() => {
        const view = getView();
        const matches = matchesRef.current;
        if (!view || matches.length === 0) return;

        EditorSearchService.replace(view, matches[currentIndex], replaceTerm);
        // 替换后需要延迟刷新搜索结果
        setTimeout(() => performSearch(searchTerm, caseSensitive), 50);
    }, [getView, currentIndex, replaceTerm, searchTerm, caseSensitive, performSearch]);

    const handleReplaceAll = useCallback(() => {
        const view = getView();
        if (!view || matchesRef.current.length === 0) return;

        EditorSearchService.replaceAll(view, matchesRef.current, replaceTerm);
        setTimeout(() => performSearch(searchTerm, caseSensitive), 50);
    }, [getView, replaceTerm, searchTerm, caseSensitive, performSearch]);

    return {
        state: {
            searchTerm,
            replaceTerm,
            caseSensitive,
            matchCount,
            currentIndex,
            showReplace,
            displayIndex: matchCount > 0 ? currentIndex + 1 : 0
        },
        actions: {
            setSearchTerm: handleSearchChange,
            setReplaceTerm,
            setCaseSensitive,
            setShowReplace,
            next: () => navigate('next'),
            prev: () => navigate('prev'),
            replace: handleReplace,
            replaceAll: handleReplaceAll,
            close: onClose
        }
    };
}

import { useState, useCallback } from 'react';
import { useEditorTabsStore, EditorTab } from '../stores/editorTabsStore';
import { useKernel } from '@/kernel/core/KernelContext';
import { X, FileText, Columns2, FolderOpen, XCircle, Files, ColumnsIcon } from 'lucide-react';
import { MenuItem } from '@/shared/components/ui/ContextMenu';

/**
 * 标签页交互逻辑 Hook
 */
export function useTabInteractions() {
    const {
        tabs, activeTabId, setActiveTab, closeTab, closeAllTabs, closeOtherTabs, reorderTabs
    } = useEditorTabsStore();
    const kernel = useKernel();

    // 状态管理
    const [contextMenu, setContextMenu] = useState<{ x: number; y: number; tabId: string } | null>(null);
    const [draggedIndex, setDraggedIndex] = useState<number | null>(null);
    const [dragOverIndex, setDragOverIndex] = useState<number | null>(null);

    // 激活逻辑
    const handleActivate = useCallback((tab: EditorTab) => {
        if (tab.id === activeTabId) return;
        if (activeTabId) kernel.emit('SAVE_CURSOR', activeTabId);
        setActiveTab(tab.id);
        kernel.emit('OPEN_FILE', tab.path);
    }, [activeTabId, setActiveTab, kernel]);

    // 拖拽逻辑
    const onDragStart = (e: React.DragEvent, index: number) => {
        setDraggedIndex(index);
        e.dataTransfer.setData('text/plain', index.toString());
        e.dataTransfer.effectAllowed = 'move';
    };

    const onDragOver = (e: React.DragEvent, index: number) => {
        e.preventDefault();
        setDragOverIndex(index);
    };

    const onDrop = (e: React.DragEvent, index: number) => {
        e.preventDefault();
        if (draggedIndex !== null && draggedIndex !== index) {
            reorderTabs(draggedIndex, index);
        }
        setDraggedIndex(null);
        setDragOverIndex(null);
    };

    const onDragEnd = () => {
        setDraggedIndex(null);
        setDragOverIndex(null);
    };

    // 右键菜单逻辑
    const getContextMenuItems = (tabId: string): MenuItem[] => [
        { label: '在此处打开', icon: <FolderOpen className="w-4 h-4" />, onClick: () => kernel.emit('REVEAL_IN_EXPLORER', tabId) },
        { label: '关闭', icon: <X className="w-4 h-4" />, onClick: () => closeTab(tabId) },
        { label: '关闭其他', icon: <XCircle className="w-4 h-4" />, onClick: () => closeOtherTabs(tabId) },
        { label: '关闭所有', icon: <XCircle className="w-4 h-4" />, onClick: closeAllTabs },
        { type: 'separator' },
        { label: '垂直分屏', icon: <Columns2 className="w-4 h-4" />, onClick: () => kernel.emit('TOGGLE_SPLIT_VIEW') }
    ];

    return {
        state: { tabs, activeTabId, contextMenu, draggedIndex, dragOverIndex },
        actions: {
            handleActivate,
            setContextMenu,
            onDragStart,
            onDragOver,
            onDrop,
            onDragEnd,
            getContextMenuItems,
            closeTab
        }
    };
}

import { Kernel } from "@/kernel/core/Kernel";
import { IPlugin } from "@/kernel/core/Kernel";
import { UISlotId } from "@/kernel/core/Constants";
import { NoteEditor } from "./components/NoteEditor";
import { useEditorStore } from "./store/editorStore";
import { useEditorTabsStore } from "./stores/editorTabsStore";
import { EditorToolbarRegistry } from './EditorToolbarRegistry';
import { InternalToolbarPlugin } from './plugins/InternalToolbarPlugin';
import { EditorPanelRegistry } from './registries/EditorPanelRegistry';
import { EditorPersistenceService } from './services/EditorPersistenceService';
import { EditorExportService } from './services/EditorExportService';
import { SearchPlugin } from './plugins/SearchPlugin';
import { EditorCoreUIPlugin } from './plugins/EditorCoreUIPlugin';
import { EditorHeaderRegistry } from '../plugin/EditorHeaderRegistry';
import { IFileSystem } from '@/kernel/interfaces/IFileSystem';
import React from "react";
import { IEditorRef, EditorCommand } from './framework/types';
import { IPluginContext } from '@/modules/plugin/types';

export class EditorPlugin implements IPlugin {
  id = "editor";
  name = "Editor";

  private onOpenFile?: (path: string | null) => void;

  activate(kernel: Kernel) {
    console.log("[EditorPlugin] Activated");

    // Register Registries & Services
    const toolbarRegistry = new EditorToolbarRegistry();
    kernel.registerService('editorToolbarRegistry', toolbarRegistry);

    const panelRegistry = new EditorPanelRegistry();
    kernel.registerService('editorPanelRegistry', panelRegistry);

    const headerRegistry = new EditorHeaderRegistry();
    kernel.registerService('editorHeaderRegistry', headerRegistry);

    const fileSystem = kernel.getService<IFileSystem>('fileSystem');
    if (fileSystem) {
      const persistenceService = new EditorPersistenceService(fileSystem);
      kernel.registerService('editorPersistenceService', persistenceService);

      const exportService = new EditorExportService(kernel);
      kernel.registerService('editorExportService', exportService);
    }

    // Activate Internal Plugins
    // 4. 定义插件激活上下文 (符合 IPluginContext)
    const searchContext: IPluginContext & { kernel: any } = {
      kernel,
      registerCommand: (id, handler) => kernel.on(id as any, handler),
      registerEditorExtension: (_ext) => { return () => { }; },
      registerEditorHeaderItem: (id, component) => {
        const hr = kernel.getService<EditorHeaderRegistry>('editorHeaderRegistry');
        return hr.registerItem({ id, component });
      },
      registerSidebarItem: (id, component, label, icon) =>
        kernel.registerUI('left-sidebar', { id, component, label, icon }),
      registerService: (id, service) => {
        kernel.registerService(id, service);
        return () => { };
      }
    };

    // 5. 激活内置插件
    const internalToolbarPlugin = new InternalToolbarPlugin();
    internalToolbarPlugin.activate(searchContext);

    SearchPlugin.activate(searchContext);
    EditorCoreUIPlugin.activate(searchContext);

    // 1. 注册主编辑器 UI
    kernel.registerUI(UISlotId.MAIN_EDITOR, {
      id: "main-editor-component",
      component: NoteEditor
    });

    // 2. 监听文件打开事件 (解耦核心)
    this.onOpenFile = (path: string | null) => {
      console.log(`[EditorPlugin] Received OPEN_FILE: ${path}`);

      // 如果 path 为 null，表示所有标签页已关闭，清空编辑器状态
      if (!path) {
        useEditorStore.getState().setCurrentFile(null);
        return;
      }

      // 获取文件名
      const fileName = path.split(/[\\/]/).pop() || 'Untitled';

      // 先打开标签页（确保标签页存在）
      useEditorTabsStore.getState().openTab(path, fileName);

      // 然后设置当前文件
      useEditorStore.getState().setCurrentFile(path);
    };

    kernel.on('OPEN_FILE', this.onOpenFile);
  }

  deactivate(kernel: Kernel) {
    // 良好的习惯：清理监听器
    if (this.onOpenFile) {
      kernel.off('OPEN_FILE', this.onOpenFile);
    }
  }
}

import React from 'react';
