/**
 * 内置工具栏插件
 * 提供 Math (Latex) 和 Emoji 选择器
 */
export class InternalToolbarPlugin implements IPlugin {
    id = 'builtin-toolbar-features';
    name = 'Built-in Toolbar Features';
    version = '1.0.0';

    activate(context: IPluginContext) {
        const kernel = (context as any).kernel;
        const registry = kernel.getService('editorToolbarRegistry') as EditorToolbarRegistry;

        // 1. 注册公式选择器
        registry.registerItem({
            id: 'insert-math',
