import React from 'react';
import { IPlugin, IPluginContext } from '@/modules/plugin/types';
import { SearchReplacePanel } from '../components/SearchReplacePanel';
import { EditorPanelRegistry } from '../registries/EditorPanelRegistry';

/**
 * SearchPlugin - 搜索与替换插件
 * 将 NoteEditor 内部的搜索逻辑彻底剥离为独立模块
 */
export const SearchPlugin: IPlugin = {
    id: 'internal.search',
    name: '搜索与替换',
    version: '1.0.0',

    activate(context: IPluginContext) {
        const kernel = (context as any).kernel;
        const panelRegistry = kernel.getService('editorPanelRegistry') as EditorPanelRegistry;

        if (!panelRegistry) {
            console.error('[SearchPlugin] EditorPanelRegistry not found');
            return;
        }

        // 1. 注册面板
        panelRegistry.registerPanel({
            id: 'search-replace',
            position: 'top',
            component: SearchReplacePanel,
            props: {
                onClose: () => panelRegistry.closePanel('search-replace')
            }
        });

        // 2. 注册命令
        context.registerCommand('editor.search.toggle', () => {
            panelRegistry.togglePanel('search-replace');
        });

        context.registerCommand('editor.search.hide', () => {
            panelRegistry.closePanel('search-replace');
        });

        // 3. 监听全局快捷键 (Ctrl+F)
        const handleKeyDown = (e: KeyboardEvent) => {
            const isCtrl = e.ctrlKey || e.metaKey;

            if (isCtrl && e.key.toLowerCase() === 'f') {
                e.preventDefault();
                e.stopPropagation();
                panelRegistry.openPanel('search-replace');
            }

            if (e.key === 'Escape' && panelRegistry.isPanelVisible('search-replace')) {
                e.preventDefault();
                e.stopPropagation();
                panelRegistry.closePanel('search-replace');
            }
        };

        window.addEventListener('keydown', handleKeyDown, true);

        // 插件停用时清理
        (this as any).cleanup = () => {
            window.removeEventListener('keydown', handleKeyDown, true);
        };
    },

    deactivate() {
        if ((this as any).cleanup) {
            (this as any).cleanup();
        }
    }
};

import React from 'react';

export interface IEditorPanel {
    id: string;
    component: React.ComponentType<any>;
    props?: any;
    /** 'top' | 'bottom' | 'side' */
    position: 'top' | 'bottom' | 'side';
}

/**
 * EditorPanelRegistry - 编辑器覆盖面板注册中心
 * 用于管理搜索面板、大纲面板等需要动态挂载到 NoteEditor 上的组件
 */
export class EditorPanelRegistry {
    private panels: Map<string, IEditorPanel> = new Map();
    private activePanelIds: Set<string> = new Set();
    private listeners: (() => void)[] = [];

    registerPanel(panel: IEditorPanel): () => void {
        this.panels.set(panel.id, panel);
        this.notify();
        return () => {
            this.panels.delete(panel.id);
            this.activePanelIds.delete(panel.id);
            this.notify();
        };
    }

    togglePanel(id: string) {
        if (this.activePanelIds.has(id)) {
            this.activePanelIds.delete(id);
        } else {
            this.activePanelIds.add(id);
        }
        this.notify();
    }

    openPanel(id: string) {
        if (this.panels.has(id)) {
            this.activePanelIds.add(id);
            this.notify();
        }
    }

    closePanel(id: string) {
        if (this.activePanelIds.has(id)) {
            this.activePanelIds.delete(id);
            this.notify();
        }
    }

    isPanelVisible(id: string): boolean {
        return this.activePanelIds.has(id);
    }

    getVisiblePanels(): IEditorPanel[] {
        return Array.from(this.activePanelIds)
            .map(id => this.panels.get(id))
            .filter((p): p is IEditorPanel => !!p);
    }

    subscribe(listener: () => void) {
        this.listeners.push(listener);
        return () => {
            this.listeners = this.listeners.filter(l => l !== listener);
        };
    }

    private notify() {
        this.listeners.forEach(l => l());
    }
}

