import { EditorView } from '@codemirror/view';
import { undo, redo } from '@codemirror/commands';
import { EditorCommand } from '../framework/types';

/**
 * 编辑器指令处理服务
 * 负责执行加粗、斜体、表格等富文本操作
 */
export class EditorCommandService {
    static execute(view: EditorView, cmd: EditorCommand, params?: any) {
        if (!view) return;
        const { state, dispatch } = view;
        const { from, to } = state.selection.main;
        const selectedText = state.sliceDoc(from, to);

        const wrapText = (symbol: string) => {
            dispatch({
                changes: { from, to, insert: `${symbol}${selectedText}${symbol}` },
                selection: { anchor: from + symbol.length, head: from + symbol.length + selectedText.length }
            });
        };

        const toggleLinePrefix = (prefix: string) => {
            const line = state.doc.lineAt(from);
            if (line.text.startsWith(prefix)) {
                dispatch({
                    changes: { from: line.from, to: line.from + prefix.length, insert: '' }
                });
            } else {
                dispatch({
                    changes: { from: line.from, to: line.from, insert: prefix },
                    selection: { anchor: from + prefix.length }
                });
            }
        };

        switch (cmd) {
            case 'BOLD': wrapText('**'); break;
            case 'ITALIC': wrapText('*'); break;
            case 'STRIKE': wrapText('~~'); break;
            case 'CODE': wrapText('`'); break;
            case 'H1': toggleLinePrefix('# '); break;
            case 'H2': toggleLinePrefix('## '); break;
            case 'H3': toggleLinePrefix('### '); break;
            case 'UL': toggleLinePrefix('- '); break;
            case 'OL': toggleLinePrefix('1. '); break;
            case 'TASK': toggleLinePrefix('- [ ] '); break;
            case 'QUOTE': toggleLinePrefix('> '); break;
            case 'LINK':
                const url = params || 'url';
                const linkText = `[${selectedText || 'link'}](${url})`;
                dispatch({ changes: { from, to, insert: linkText } });
                break;
            case 'TABLE': {
                const line = state.doc.lineAt(from);
                const isLineEmpty = line.text.trim() === '';
                const insertPos = isLineEmpty ? from : line.to;
                const prevLine = line.number > 1 ? state.doc.line(line.number - 1) : null;

                let prefix = '';
                if (!isLineEmpty) {
                    prefix = '\n\n';
                } else if (prevLine && prevLine.text.trim() !== '') {
                    prefix = '\n';
                }

                const suffix = '\n';
                const tableTemplate = `${prefix}| 列1 | 列2 | 列3 |\n|---|---|---|\n| 内容 | 内容 | 内容 |${suffix}`;
                dispatch({
                    changes: { from: insertPos, insert: tableTemplate },
                    selection: { anchor: insertPos + tableTemplate.length }
                });
                break;
            }
            case 'UNDO': undo(view); break;
            case 'REDO': redo(view); break;
        }

        view.focus();
    }
}

import { IFileSystem } from '@/kernel/interfaces/IFileSystem';
import { Kernel } from '@/kernel/core/Kernel';

export interface ExportOptions {
    basePath?: string;
    title?: string;
}

export class EditorExportService {
    private fileSystem: IFileSystem;
    private kernel: Kernel;

    constructor(kernel: Kernel) {
        this.kernel = kernel;
        this.fileSystem = kernel.getService<IFileSystem>('fileSystem');
    }

    /**
     * 核心导出方法：负责渲染、净化与分发
     */
    async exportFile(content: string, savePath: string, format: 'md' | 'pdf' | 'mht', options: ExportOptions = {}): Promise<void> {
        if (format === 'md') {
            await this.fileSystem.saveFile(savePath, content);
            return;
        }

        // 渲染 HTML
        const markdownService = this.kernel.getService<any>('markdownService');
        if (!markdownService) throw new Error('MarkdownService not found');

        const rawHtml = await markdownService.render(content);

        // 动态导入 DOMPurify 以减小主包体积
        const DOMPurify = (await import('dompurify')).default;
        const cleanHtml = DOMPurify.sanitize(rawHtml as string);

        if (format === 'pdf') {
            await this.fileSystem.exportToPDF(cleanHtml, savePath, { basePath: options.basePath });
        } else if (format === 'mht') {
            // 注意：项目中 exportToWord 实际上实现了 MHTML 导出
            await this.fileSystem.exportToWord(cleanHtml, savePath, { basePath: options.basePath });
        }
    }

    /**
     * @deprecated 请使用集成的 exportFile 方法
     */
    async exportToMHT(fileName: string, content: string, title: string = ''): Promise<boolean> {
        try {
            await this.exportFile(content, fileName, 'mht', { title });
            return true;
        } catch (e) {
            console.error('[EditorExportService] MHT Export failed:', e);
            return false;
        }
    }
}

import { EditorView } from '@codemirror/view';
import { SearchQuery, setSearchQuery } from '@codemirror/search';
import { EditorSelection } from '@codemirror/state';
import { setActiveMatchEffect } from '../cm-extensions/searchHighlight';

/**
 * 编辑器搜索服务
 * 封装所有与 CodeMirror 搜索/替换相关的底层操作
 */
export class EditorSearchService {
    /**
     * 执行搜索并获取匹配列表
     */
    static findMatches(view: EditorView, term: string, caseSensitive: boolean) {
        if (!view || !term) return [];

        const query = new SearchQuery({
            search: term,
            caseSensitive,
            regexp: false,
            wholeWord: false,
        });

        // 应用高亮效果
        view.dispatch({
            effects: setSearchQuery.of(query)
        });

        const cursor = query.getCursor(view.state);
        const matches: { from: number, to: number }[] = [];
        let result = cursor.next();
        while (!result.done) {
            matches.push({ from: result.value.from, to: result.value.to });
            result = cursor.next();
        }
        return matches;
    }

    /**
     * 跳转到指定索引的匹配项
     */
    static jumpToMatch(view: EditorView, match: { from: number, to: number }) {
        if (!view || !match) return;

        const docLength = view.state.doc.length;
        if (match.from < 0 || match.to > docLength || match.from > match.to) return;

        view.dispatch({
            selection: EditorSelection.single(match.from, match.to),
            effects: [
                EditorView.scrollIntoView(match.from, { y: 'center', yMargin: 50 }),
                setActiveMatchEffect.of({ from: match.from, to: match.to })
            ]
        });
    }

    /**
     * 清除搜索状态
     */
    static clearSearch(view: EditorView) {
        if (!view) return;
        try {
            view.dispatch({
                effects: [
                    setSearchQuery.of(new SearchQuery({
                        search: '',
                        caseSensitive: false,
                        regexp: false,
                        wholeWord: false,
                    })),
                    setActiveMatchEffect.of(null)
                ]
            });
        } catch (e) { }
    }

    /**
     * 替换单个匹配
     */
    static replace(view: EditorView, match: { from: number, to: number }, text: string) {
        if (!view || !match) return;
        view.dispatch({
            changes: { from: match.from, to: match.to, insert: text }
        });
    }

    /**
     * 替换所有匹配
     */
    static replaceAll(view: EditorView, matches: { from: number, to: number }[], text: string) {
        if (!view || matches.length === 0) return;
        const docLength = view.state.doc.length;
        const validChanges = matches
            .filter(m => m.from >= 0 && m.to <= docLength && m.from <= m.to)
            .sort((a, b) => b.from - a.from)
            .map(m => ({ from: m.from, to: m.to, insert: text }));

        view.dispatch({ changes: validChanges });
    }
}

import { EditorView } from '@codemirror/view';

export interface SyncState {
    cursorLine: number;
    content: string;
}

export class EditorSyncService {
    private mainView: EditorView | null = null;
    private previewView: EditorView | null = null;
    private isSyncing = false;
    private debounceTimer: NodeJS.Timeout | null = null;

    setViews(main: EditorView | null, preview: EditorView | null) {
        this.mainView = main;
        this.previewView = preview;
    }

    /**
     * 高效内容同步
     * 使用直接 dispatch 避免 React 全量重渲染
     */
    syncContent(content: string, cursorLine: number, force: boolean = false) {
        if (!this.previewView) return;

        if (this.debounceTimer) clearTimeout(this.debounceTimer);

        this.debounceTimer = setTimeout(() => {
            if (!this.previewView) return;

            // 1. 内容比对：如果一致，仅同步滚动
            const currentDoc = this.previewView.state.doc.toString();
            const hasChanged = currentDoc !== content;

            if (hasChanged || force) {
                const lines = content.split('\n');
                const targetLineIndex = Math.min(cursorLine - 1, lines.length - 1);
                let charOffset = 0;
                for (let i = 0; i < targetLineIndex; i++) {
                    charOffset += lines[i].length + 1;
                }

                // 原子操作：更新文本 + 滚动到对应位置
                this.previewView.dispatch({
                    changes: { from: 0, to: this.previewView.state.doc.length, insert: content },
                    effects: EditorView.scrollIntoView(charOffset, { y: 'nearest', yMargin: 20 })
                });
            } else {
                // 内容未变，仅同步滚动
                this.syncScroll(cursorLine);
            }
        }, 80); // 略微收紧防抖，因为 dispatch 比重渲染快得多
    }

    /**
     * 仅同步滚动位置
     */
    syncScroll(cursorLine: number) {
        if (!this.previewView) return;

        try {
            const docLines = this.previewView.state.doc.lines;
            const targetLine = Math.min(cursorLine, docLines);
            if (targetLine < 1) return;

            const lineInfo = this.previewView.state.doc.line(targetLine);
            this.previewView.dispatch({
                effects: EditorView.scrollIntoView(lineInfo.from, { y: 'nearest', yMargin: 20 })
            });
        } catch (e) {
            // Silently ignore scroll errors
        }
    }

    dispose() {
        if (this.debounceTimer) clearTimeout(this.debounceTimer);
        this.mainView = null;
        this.previewView = null;
    }
}

import { EditorView } from "@codemirror/view";

/**
 * 表格数据接口
 */
export interface TableData {
    headers: string[];
    rows: string[][];
    from: number;
    to: number;
}

/**
 * 解析 Markdown 表格
 */
export function parseMarkdownTable(text: string, startPos: number): TableData | null {
    const lines = text.split('\n');
    if (lines.length < 2) return null;

    const parseRow = (line: string): string[] => {
        const parts = line.trim().split('|');
        if (parts[0] === '') parts.shift();
        if (parts[parts.length - 1] === '') parts.pop();
        return parts.map(p => p.trim());
    };

    const headerRow = parseRow(lines[0]);
    const separatorRow = parseRow(lines[1]);

    if (headerRow.length === 0 || separatorRow.length === 0) return null;
    const isSeparator = separatorRow.every(cell => /^:?-+:?$/.test(cell));
    if (!isSeparator) return null;

    const rows: string[][] = [];
    for (let i = 2; i < lines.length; i++) {
        if (!lines[i].includes('|')) break;
        const rowData = parseRow(lines[i]);
        if (rowData.length > 0) rows.push(rowData);
    }

    return {
        headers: headerRow,
        rows,
        from: startPos,
        to: startPos + text.length
    };
}

/**
 * 生成 Markdown 表格 (严格矩形化)
 */
export function generateMarkdown(headers: string[], rows: string[][]): string {
    const colCount = Math.max(headers.length, ...rows.map(r => r.length));
    const pad = (arr: string[], len: number) => [...arr, ...Array(Math.max(0, len - arr.length)).fill('')];

    const h = pad(headers, colCount);
    const r = rows.map(row => pad(row, colCount));

    const lines = [
        `| ${h.join(' | ')} |`,
        `| ${Array(colCount).fill('---').join(' | ')} |`,
        ...r.map(row => `| ${row.join(' | ')} |`)
    ];
    return lines.join('\n');
}

/**
 * 从文档中动态计算表格的实际结束位置
 */
export function findTableEndPosition(view: EditorView, from: number): number {
    try {
        const doc = view.state.doc;
        const startLine = doc.lineAt(from).number;
        let lastTableLine = startLine;

        for (let i = startLine; i <= doc.lines; i++) {
            const lineText = doc.line(i).text.trim();
            if (lineText.startsWith('|') || (i === startLine + 1 && lineText.includes('|') && lineText.includes('-'))) {
                lastTableLine = i;
            } else {
                break;
            }
        }
        return doc.line(lastTableLine).to;
    } catch (e) {
        return from;
    }
}
